{
  "name": "FleetTrack HRGA",
  "description": "A comprehensive office car usage monitoring system for HRGA professionals, featuring form submissions, fleet tracking, and AI-powered usage analysis.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Car {
  id: string;
  name: string;
  plateNumber: string;
  status: 'available' | 'in-use' | 'maintenance';
}

export interface UsageLog {
  id: string;
  carId: string;
  carName: string;
  driverName: string;
  department: string;
  purpose: string;
  departureTime: string;
  arrivalTime?: string;
  startOdometer: number;
  endOdometer?: number;
  destination: string;
  notes?: string;
  status: 'active' | 'completed';
}

export interface AppState {
  cars: Car[];
  logs: UsageLog[];
}

import React from 'react';
import { Car } from './types';

