import { GoogleGenAI } from "@google/genai";
import { UsageLog } from "../types";

export const analyzeFleetUsage = async (logs: UsageLog[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Saya adalah HRGA. Ini adalah data penggunaan mobil kantor kami akhir-akhir ini:
    ${JSON.stringify(logs.map(l => ({ 
      car: l.carName, 
      driver: l.driverName, 
      dept: l.department, 
      dist: l.endOdometer && l.startOdometer ? l.endOdometer - l.startOdometer : 0,
      purpose: l.purpose 
    })))}

    Berdasarkan data ini, tolong buatkan ringkasan singkat dalam Bahasa Indonesia:
    1. Siapa driver/departemen yang paling sering menggunakan mobil?
    2. Mobil mana yang paling tinggi kilometernya?
    3. Adakah indikasi penyalahgunaan atau saran perawatan (misal mobil tertentu butuh servis)?
    4. Saran untuk efisiensi ke depannya.

    Format jawaban dengan poin-poin yang profesional dan ramah.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return "Gagal melakukan analisis data. Silakan coba lagi nanti.";
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Car, UsageLog } from './types';
import { INITIAL_CARS, Icons } from './constants';
import FormPage from './pages/FormPage';
import DashboardPage from './pages/DashboardPage';
import HistoryPage from './pages/HistoryPage';
import InsightsPage from './pages/InsightsPage';

function Sidebar() {
  const location = useLocation();

  const navItems = [
    { path: '/', label: 'Isi Form Pinjam', icon: <Icons.Clipboard /> },
    { path: '/dashboard', label: 'Monitor Fleet', icon: <Icons.Layout /> },
    { path: '/history', label: 'Riwayat Lengkap', icon: <Icons.History /> },
    { path: '/insights', label: 'AI Analisis', icon: <Icons.Sparkles /> },
  ];

  return (
    <div className="hidden md:flex flex-col w-64 bg-white border-r border-slate-200 min-h-screen sticky top-0">
      <div className="p-6 border-b border-slate-100 flex items-center gap-3">
        <div className="p-2 bg-blue-600 rounded-lg text-white">
          <Icons.Car />
        </div>
        <span className="font-bold text-slate-800 text-xl tracking-tight">FleetTrack</span>
      </div>
      <nav className="flex-1 p-4 space-y-1">
        {navItems.map((item) => (
          <Link
            key={item.path}
            to={item.path}
            className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-colors font-medium ${
              location.pathname === item.path
                ? 'bg-blue-50 text-blue-600'
                : 'text-slate-600 hover:bg-slate-50'
            }`}
          >
            {item.icon}
            {item.label}
          </Link>
        ))}
      </nav>
      <div className="p-4 border-t border-slate-100">
        <div className="bg-slate-900 rounded-xl p-4 text-white">
          <p className="text-xs text-slate-400 mb-1">HRGA Portal</p>
          <p className="font-medium text-sm">Monitoring System</p>
        </div>
      </div>
    </div>
  );
}

function BottomNav() {
  const location = useLocation();
  const navItems = [
    { path: '/', label: 'Form', icon: <Icons.Clipboard /> },
    { path: '/dashboard', label: 'Monitor', icon: <Icons.Layout /> },
    { path: '/history', label: 'History', icon: <Icons.History /> },
    { path: '/insights', label: 'AI', icon: <Icons.Sparkles /> },
  ];

  return (
    <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around p-2 pb-safe z-50">
      {navItems.map((item) => (
        <Link
          key={item.path}
          to={item.path}
          className={`flex flex-col items-center p-2 rounded-lg transition-colors ${
            location.pathname === item.path ? 'text-blue-600' : 'text-slate-500'
          }`}
        >
          {item.icon}
          <span className="text-[10px] mt-1 font-medium">{item.label}</span>
        </Link>
      ))}
    </div>
  );
}

export default function App() {
  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('fleet_cars', JSON.stringify(cars));
  }, [cars]);

  useEffect(() => {
    localStorage.setItem('fleet_logs', JSON.stringify(logs));
  }, [logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs([newLog, ...logs]);
    setCars(prev => prev.map(c => 
      c.id === newLog.carId ? { ...c, status: 'in-use' } : c
    ));
  };

  const completeLog = (logId: string, endOdo: number) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;

    setLogs(prev => prev.map(l => 
      l.id === logId 
        ? { ...l, status: 'completed' as const, endOdometer: endOdo, arrivalTime: new Date().toISOString() } 
        : l
    ));

    setCars(prev => prev.map(c => 
      c.id === logToFinish.carId ? { ...c, status: 'available' } : c
    ));
  };

  return (
    <HashRouter>
      <div className="flex min-h-screen w-full text-slate-900">
        <Sidebar />
        <main className="flex-1 w-full pb-20 md:pb-0 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/dashboard" element={<DashboardPage cars={cars} logs={logs} onComplete={completeLog} />} />
            <Route path="/history" element={<HistoryPage logs={logs} />} />
            <Route path="/insights" element={<InsightsPage logs={logs} />} />
          </Routes>
        </main>
        <BottomNav />
      </div>
    </HashRouter>
  );
}

import React, { useState } from 'react';
import { Car, UsageLog } from '../types';
import { DEPARTMENTS } from '../constants';

interface Props {
  cars: Car[];
  onSubmit: (log: UsageLog) => void;
}

export default function FormPage({ cars, onSubmit }: Props) {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    carId: '',
    driverName: '',
    department: '',
    purpose: '',
    startOdometer: '',
    destination: '',
    notes: ''
  });

  const availableCars = cars.filter(c => c.status === 'available');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const selectedCar = cars.find(c => c.id === formData.carId);
    if (!selectedCar) return;

    const newLog: UsageLog = {
      id: crypto.randomUUID(),
      carId: formData.carId,
      carName: `${selectedCar.name} (${selectedCar.plateNumber})`,
      driverName: formData.driverName,
      department: formData.department,
      purpose: formData.purpose,
      departureTime: new Date().toISOString(),
      startOdometer: parseInt(formData.startOdometer),
      destination: formData.destination,
      notes: formData.notes,
      status: 'active'
    };

    onSubmit(newLog);
    setSubmitted(true);
    setFormData({
      carId: '',
      driverName: '',
      department: '',
      purpose: '',
      startOdometer: '',
      destination: '',
      notes: ''
    });

    setTimeout(() => setSubmitted(false), 3000);
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8">
      <div className="mb-8">
        <h1 className="text-2xl md:text-3xl font-bold text-slate-900 mb-2">Form Penggunaan Mobil</h1>
        <p className="text-slate-500">Silakan isi detail perjalanan Anda sebelum keberangkatan.</p>
      </div>

      {submitted && (
        <div className="mb-6 p-4 bg-green-50 border border-green-200 text-green-700 rounded-xl flex items-center gap-3">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
          <span className="font-medium">Data berhasil disimpan! Selamat berkendara.</span>
        </div>
      )}

      <form onSubmit={handleSubmit} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 md:p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700 block">Pilih Mobil</label>
              <select
                required
                value={formData.carId}
                onChange={e => setFormData({ ...formData, carId: e.target.value })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all appearance-none"
              >
                <option value="">-- Pilih Mobil Tersedia --</option>
                {availableCars.map(car => (
                  <option key={car.id} value={car.id}>
                    {car.name} - {car.plateNumber}
                  </option>
                ))}
              </select>
              {availableCars.length === 0 && (
                <p className="text-xs text-amber-600 font-medium">Maaf, saat ini semua mobil sedang digunakan.</p>
              )}
            </div>

            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700 block">Departemen</label>
              <select
                required
                value={formData.department}
                onChange={e => setFormData({ ...formData, department: e.target.value })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all appearance-none"
              >
                <option value="">-- Pilih Departemen --</option>
                {DEPARTMENTS.map(dept => (
                  <option key={dept} value={dept}>{dept}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700 block">Nama Driver / Pengguna</label>
              <input
                type="text"
                required
                placeholder="Misal: Ahmad Fauzi"
                value={formData.driverName}
                onChange={e => setFormData({ ...formData, driverName: e.target.value })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700 block">Odometer Awal (KM)</label>
              <input
                type="number"
                required
                placeholder="Contoh: 12500"
                value={formData.startOdometer}
                onChange={e => setFormData({ ...formData, startOdometer: e.target.value })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700 block">Tujuan</label>
            <input
              type="text"
              required
              placeholder="Misal: Kantor Cabang Bekasi / Meeting Vendor"
              value={formData.destination}
              onChange={e => setFormData({ ...formData, destination: e.target.value })}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-slate-700 block">Tujuan Perjalanan (Detail)</label>
            <textarea
              required
              rows={3}
              placeholder="Jelaskan secara singkat urusan kantor yang dilakukan..."
              value={formData.purpose}
              onChange={e => setFormData({ ...formData, purpose: e.target.value })}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all resize-none"
            />
          </div>
        </div>

        <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end">
          <button
            type="submit"
            className="w-full md:w-auto px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-xl transition-all shadow-lg shadow-blue-200 active:scale-95 flex items-center justify-center gap-2"
          >
            Submit Keberangkatan
          </button>
        </div>
      </form>
    </div>
  );
}

import React, { useState } from 'react';
import { Car, UsageLog } from '../types';

interface Props {
  cars: Car[];
  logs: UsageLog[];
  onComplete: (id: string, odo: number) => void;
}

export default function DashboardPage({ cars, logs, onComplete }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [completeDialog, setCompleteDialog] = useState<string | null>(null);
  const [endOdo, setEndOdo] = useState('');

  const stats = {
    total: cars.length,
    available: cars.filter(c => c.status === 'available').length,
    inUse: cars.filter(c => c.status === 'in-use').length,
    maintenance: cars.filter(c => c.status === 'maintenance').length,
  };

  const handleFinish = (id: string) => {
    if (!endOdo) return alert('Odometer akhir harus diisi');
    onComplete(id, parseInt(endOdo));
    setCompleteDialog(null);
    setEndOdo('');
  };

  return (
    <div className="p-4 md:p-8 space-y-8">
      <div>
        <h1 className="text-2xl font-bold text-slate-900 mb-6">Status Fleet Real-time</h1>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard label="Total Mobil" value={stats.total} color="bg-slate-100 text-slate-700" />
          <StatCard label="Tersedia" value={stats.available} color="bg-green-100 text-green-700" />
          <StatCard label="Digunakan" value={stats.inUse} color="bg-blue-100 text-blue-700" />
          <StatCard label="Servis" value={stats.maintenance} color="bg-amber-100 text-amber-700" />
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-6">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></span>
            Mobil Sedang Beroperasi ({activeLogs.length})
          </h2>

          {activeLogs.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center text-slate-400">
              Tidak ada mobil yang sedang di jalan saat ini.
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {activeLogs.map(log => (
                <div key={log.id} className="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm hover:shadow-md transition-shadow">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="font-bold text-slate-900">{log.carName}</h3>
                      <p className="text-xs text-slate-500 font-medium">{log.department}</p>
                    </div>
                    <span className="px-2 py-1 bg-blue-50 text-blue-600 text-[10px] font-bold rounded uppercase tracking-wider">Active</span>
                  </div>

                  <div className="space-y-3 mb-5">
                    <div className="flex items-center gap-3 text-sm">
                      <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M19 21v-2a4 4 0 0 0-4-4H9a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
                      </div>
                      <div>
                        <p className="text-xs text-slate-400">Driver</p>
                        <p className="font-medium text-slate-700">{log.driverName}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 text-sm">
                      <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>
                      </div>
                      <div>
                        <p className="text-xs text-slate-400">Tujuan</p>
                        <p className="font-medium text-slate-700 truncate max-w-[150px]">{log.destination}</p>
                      </div>
                    </div>
                  </div>

                  <button 
                    onClick={() => setCompleteDialog(log.id)}
                    className="w-full py-2 bg-slate-900 text-white rounded-lg text-sm font-semibold hover:bg-slate-800 transition-colors"
                  >
                    Konfirmasi Kembali
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="bg-white border border-slate-200 rounded-2xl p-6 h-fit">
          <h2 className="font-bold text-slate-900 mb-4">Daftar Kendaraan</h2>
          <div className="space-y-4">
            {cars.map(car => (
              <div key={car.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-slate-50 transition-colors border border-transparent hover:border-slate-100">
                <div className="flex items-center gap-3">
                  <div className={`w-2 h-2 rounded-full ${
                    car.status === 'available' ? 'bg-green-500' : car.status === 'in-use' ? 'bg-blue-500' : 'bg-amber-500'
                  }`}></div>
                  <div>
                    <p className="font-semibold text-sm text-slate-800">{car.name}</p>
                    <p className="text-[10px] text-slate-500 font-mono">{car.plateNumber}</p>
                  </div>
                </div>
                <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase ${
                  car.status === 'available' ? 'bg-green-50 text-green-600' : car.status === 'in-use' ? 'bg-blue-50 text-blue-600' : 'bg-amber-50 text-amber-600'
                }`}>
                  {car.status}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {completeDialog && (
