                filteredLogs.map(log => (
                  <tr key={log.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <p className="font-semibold text-slate-800">{log.driverName}</p>
                      <p className="text-xs text-slate-500">{log.department}</p>
                    </td>
                    <td className="px-6 py-4">
                      <p className="font-medium text-slate-700">{log.carName}</p>
                      <p className="text-xs text-slate-500 truncate max-w-xs">{log.destination}</p>
