                        </span>
                        {log.arrivalTime && (
                          <span className="text-xs text-blue-600 flex items-center gap-1">
                            <span className="w-1 h-1 rounded-full bg-blue-500"></span> In: {formatDate(log.arrivalTime)}
                          </span>
