                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-xs space-y-0.5">
                        <p className="text-slate-500">Awal: {log.startOdometer} KM</p>
                        {log.endOdometer && (
                          <>
                            <p className="text-slate-500">Akhir: {log.endOdometer} KM</p>
                            <p className="text-blue-600 font-bold">Total: {log.endOdometer - log.startOdometer} KM</p>
