interface Props {
  logs: UsageLog[];
}

export default function InsightsPage({ logs }: Props) {
  const [loading, setLoading] = useState(false);
  const [insight, setInsight] = useState<string | null>(null);

  const handleAnalyze = async () => {
    if (logs.length === 0) return alert('Butuh data riwayat untuk melakukan analisis.');
    setLoading(true);
    const result = await analyzeFleetUsage(logs);
    setInsight(result || "Tidak ada hasil analisis.");
    setLoading(false);
  };

  return (
    <div className="p-4 md:p-8 max-w-4xl">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-slate-900 mb-2">Fleet AI Insights</h1>
        <p className="text-slate-500">Gunakan AI untuk menganalisis pola penggunaan mobil dan mendapatkan saran efisiensi.</p>
      </div>

      {!insight && !loading && (
        <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl p-8 text-white shadow-xl shadow-blue-200">
          <div className="flex items-center gap-4 mb-6">
            <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-md">
              <Icons.Sparkles />
            </div>
            <div>
              <h2 className="text-xl font-bold">Butuh Analisis Bulanan?</h2>
              <p className="text-blue-100 text-sm opacity-90">Hemat waktu HRGA dengan laporan otomatis berbasis data.</p>
            </div>
          </div>

          <div className="space-y-4 mb-8">
            <FeatureItem text="Identifikasi driver paling aktif" />
            <FeatureItem text="Deteksi anomali penggunaan bensin/jarak" />
            <FeatureItem text="Rekomendasi jadwal servis rutin" />
          </div>

          <button
            onClick={handleAnalyze}
            disabled={logs.length === 0}
            className="w-full md:w-auto px-10 py-4 bg-white text-blue-700 font-bold rounded-2xl hover:bg-blue-50 transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
          >
            Mulai Analisis Sekarang
          </button>
          {logs.length === 0 && <p className="mt-2 text-xs text-blue-200">Belum ada data logs untuk dianalisis.</p>}
        </div>
      )}

      {loading && (
        <div className="bg-white border border-slate-200 rounded-3xl p-12 text-center">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
          <h3 className="text-lg font-bold text-slate-800 mb-2">Gemini Sedang Berpikir...</h3>
          <p className="text-slate-500">Menganalisis {logs.length} entri data untuk Anda.</p>
        </div>
      )}

      {insight && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm">
            <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center gap-2">
                <div className="text-blue-600"><Icons.Sparkles /></div>
                <span className="font-bold text-slate-800 uppercase text-xs tracking-widest">AI Generated Report</span>
              </div>
              <button 
                onClick={() => setInsight(null)}
                className="text-xs text-slate-400 hover:text-slate-600 font-bold"
              >
                Hapus
              </button>
            </div>
            <div className="p-6 md:p-10 prose prose-slate max-w-none">
              <div className="whitespace-pre-wrap text-slate-700 leading-relaxed font-medium">
                {insight}
              </div>
            </div>
          </div>

          <div className="flex justify-center">
            <button
              onClick={handleAnalyze}
              className="text-blue-600 font-bold text-sm hover:underline"
            >
              Update Analisis Terbaru
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

