import React, { useState } from 'react';
import { Car, UsageLog } from '../types';
import { DEPARTMENTS, Icons } from '../constants';

interface Props {
  cars: Car[];
  onSubmit: (log: UsageLog) => void;
}

export default function FormPage({ cars, onSubmit }: Props) {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    carId: '',
    driverName: '',
    department: '',
    purpose: '',
    startOdometer: '',
    destination: '',
    notes: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const selectedCar = cars.find(c => c.id === formData.carId);
    if (!selectedCar || selectedCar.status !== 'available') {
      alert('Silakan pilih mobil yang tersedia terlebih dahulu.');
      return;
    }

    const newLog: UsageLog = {
      id: crypto.randomUUID(),
      carId: formData.carId,
      carName: `${selectedCar.name} (${selectedCar.plateNumber})`,
      driverName: formData.driverName,
      department: formData.department,
      purpose: formData.purpose,
      departureTime: new Date().toISOString(),
      startOdometer: parseInt(formData.startOdometer),
      destination: formData.destination,
      notes: formData.notes,
      status: 'active'
    };

    onSubmit(newLog);
    setSubmitted(true);
    setFormData({
      carId: '',
      driverName: '',
      department: '',
      purpose: '',
      startOdometer: '',
      destination: '',
      notes: ''
    });

    setTimeout(() => setSubmitted(false), 3000);
  };

  const handleCarSelect = (car: Car) => {
    if (car.status === 'available') {
      setFormData({ ...formData, carId: car.id });
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-4 md:p-8">
      <div className="mb-8">
        <h1 className="text-2xl md:text-3xl font-bold text-slate-900 mb-2">Form Penggunaan Mobil</h1>
        <p className="text-slate-500">Pilih armada yang tersedia dan isi detail perjalanan Anda.</p>
      </div>

      {submitted && (
        <div className="mb-6 p-4 bg-green-50 border border-green-200 text-green-700 rounded-xl flex items-center gap-3 animate-in fade-in zoom-in duration-300">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
          <span className="font-medium">Data berhasil disimpan! Selamat berkendara.</span>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-8">
        {/* Visual Car Selector */}
        <div className="space-y-4">
          <label className="text-sm font-bold text-slate-700 uppercase tracking-wider block">Pilih Armada</label>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {cars.map((car) => {
              const isSelected = formData.carId === car.id;
              const isAvailable = car.status === 'available';

              return (
                <div
                  key={car.id}
                  onClick={() => handleCarSelect(car)}
                  className={`relative cursor-pointer group transition-all duration-200 rounded-2xl border-2 p-5 flex items-center gap-4 ${
                    isSelected 
                      ? 'border-blue-600 bg-blue-50 shadow-md shadow-blue-100' 
                      : isAvailable
                        ? 'border-slate-200 bg-white hover:border-blue-300 hover:shadow-sm'
                        : 'border-slate-100 bg-slate-50 opacity-60 cursor-not-allowed'
                  }`}
                >
                  <div className={`p-3 rounded-xl ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors'}`}>
                    <Icons.Car />
                  </div>

                  <div className="flex-1">
                    <div className="flex items-center justify-between mb-1">
                      <h3 className={`font-bold ${isSelected ? 'text-blue-900' : 'text-slate-800'}`}>{car.name}</h3>
                      {isSelected && (
                        <div className="text-blue-600">
                          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                        </div>
                      )}
                    </div>
                    <p className="text-xs font-mono text-slate-500 mb-2">{car.plateNumber}</p>

                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-tight ${
                      car.status === 'available' 
                        ? 'bg-green-100 text-green-700' 
                        : car.status === 'in-use' 
                          ? 'bg-blue-100 text-blue-700' 
                          : 'bg-amber-100 text-amber-700'
                    }`}>
                      {car.status === 'available' ? 'Tersedia' : car.status === 'in-use' ? 'Sedang Dipakai' : 'Servis'}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-6 md:p-8 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700 block">Nama Driver / Pengguna</label>
                <input
                  type="text"
                  required
                  placeholder="Misal: Ahmad Fauzi"
                  value={formData.driverName}
                  onChange={e => setFormData({ ...formData, driverName: e.target.value })}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700 block">Departemen</label>
                <select
                  required
                  value={formData.department}
                  onChange={e => setFormData({ ...formData, department: e.target.value })}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all appearance-none"
                >
                  <option value="">-- Pilih Departemen --</option>
                  {DEPARTMENTS.map(dept => (
                    <option key={dept} value={dept}>{dept}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700 block">Odometer Awal (KM)</label>
                <input
                  type="number"
                  required
                  placeholder="Contoh: 12500"
                  value={formData.startOdometer}
                  onChange={e => setFormData({ ...formData, startOdometer: e.target.value })}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all font-mono"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700 block">Tujuan Lokasi</label>
                <input
                  type="text"
                  required
                  placeholder="Misal: Kantor Cabang Bekasi"
                  value={formData.destination}
                  onChange={e => setFormData({ ...formData, destination: e.target.value })}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700 block">Detail Keperluan</label>
              <textarea
                required
                rows={3}
                placeholder="Jelaskan secara singkat urusan kantor yang dilakukan..."
                value={formData.purpose}
                onChange={e => setFormData({ ...formData, purpose: e.target.value })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all resize-none"
              />
            </div>
          </div>

          <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end">
            <button
              type="submit"
              disabled={!formData.carId}
              className={`w-full md:w-auto px-10 py-4 font-bold rounded-2xl transition-all shadow-lg active:scale-95 flex items-center justify-center gap-2 ${
                formData.carId 
                  ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200' 
                  : 'bg-slate-300 text-slate-500 cursor-not-allowed shadow-none'
              }`}
            >
              <Icons.Car />
              Submit Keberangkatan
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}

