                      ? 'border-slate-200 bg-white hover:border-blue-300 hover:shadow-sm'
                      : 'border-slate-100 bg-slate-50 opacity-60 cursor-not-allowed grayscale'
                }`}
              >
                <div className={`p-3 rounded-xl ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors'}`}>
                  <Icons.Car />
                </div>

                <div className="flex-1">
                  <div className="flex items-center justify-between mb-1">
                    <h3 className={`font-bold ${isSelected ? 'text-blue-900' : 'text-slate-800'}`}>{car.name}</h3>
                    {isSelected && (
                      <div className="text-blue-600 bg-white rounded-full p-0.5 border border-blue-200">
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                      </div>
                    )}
                  </div>
                  <p className="text-xs font-mono text-slate-500 mb-2">{car.plateNumber}</p>

                  <div className="flex items-center gap-2">
                    <span className={`text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-wider ${
                      car.status === 'available' 
                        ? 'bg-green-100 text-green-700' 
                        : 'bg-slate-200 text-slate-500'
                    }`}>
                      {car.status === 'available' ? 'Tersedia' : car.status === 'in-use' ? 'Dipakai' : 'Servis'}
                    </span>
                    {car.status === 'available' && !formData.carId && (
                      <span className="text-[10px] text-blue-600 font-bold animate-pulse">Klik untuk pilih</span>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* STEP 2: ISI FORM (Only if car is selected) */}
        {formData.carId && (
          <form 
            onSubmit={handleSubmit} 
            className="animate-in slide-in-from-top-4 fade-in duration-500 space-y-6"
          >
            <div className="flex items-center gap-2">
              <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <span className="flex items-center justify-center w-5 h-5 bg-slate-900 text-white rounded-full text-[10px]">2</span>
                Lengkapi Detail Perjalanan
              </h2>
              <div className="flex-1 h-[1px] bg-slate-200"></div>
            </div>

            <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden ring-4 ring-blue-50">
              <div className="bg-blue-600 px-6 py-4 text-white flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <Icons.Car />
                  <div>
                    <p className="text-[10px] font-bold uppercase opacity-80 leading-none">Anda Memilih:</p>
                    <p className="font-bold text-sm leading-tight">{selectedCar?.name} - {selectedCar?.plateNumber}</p>
                  </div>
                </div>
                <div className="text-[10px] font-mono bg-white/20 px-2 py-1 rounded">ID: {formData.carId}</div>
              </div>

              <div className="p-6 md:p-8 space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-semibold text-slate-700 block">Nama Driver</label>
                    <input
                      type="text"
                      required
                      placeholder="Nama lengkap pengemudi"
                      value={formData.driverName}
                      onChange={e => setFormData({ ...formData, driverName: e.target.value })}
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-semibold text-slate-700 block">Departemen</label>
                    <select
                      required
                      value={formData.department}
                      onChange={e => setFormData({ ...formData, department: e.target.value })}
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all appearance-none"
                    >
                      <option value="">-- Pilih Departemen --</option>
                      {DEPARTMENTS.map(dept => (
                        <option key={dept} value={dept}>{dept}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-semibold text-slate-700 block">Odometer Awal (KM)</label>
                    <input
                      type="number"
                      required
                      placeholder="Lihat di dashboard mobil"
                      value={formData.startOdometer}
                      onChange={e => setFormData({ ...formData, startOdometer: e.target.value })}
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all font-mono"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-semibold text-slate-700 block">Tujuan Perjalanan</label>
                    <input
                      type="text"
                      required
                      placeholder="Misal: Meeting Vendor Kelapa Gading"
                      value={formData.destination}
                      onChange={e => setFormData({ ...formData, destination: e.target.value })}
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 block">Keperluan Detail</label>
                  <textarea
                    required
                    rows={2}
                    placeholder="Contoh: Mengantar dokumen penawaran dan meeting rutin..."
                    value={formData.purpose}
                    onChange={e => setFormData({ ...formData, purpose: e.target.value })}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 transition-all resize-none"
                  />
                </div>
              </div>

              <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end">
                <button
                  type="submit"
                  className="w-full md:w-auto px-10 py-4 bg-slate-900 text-white font-bold rounded-2xl hover:bg-slate-800 transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                  Konfirmasi Keberangkatan
                </button>
              </div>
            </div>
          </form>
        )}
      </div>

      {!formData.carId && (
        <div className="mt-12 p-8 border-2 border-dashed border-slate-200 rounded-3xl text-center">
          <div className="w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
            <Icons.Car />
          </div>
          <p className="text-slate-500 font-medium">Silakan pilih salah satu mobil yang <span className="text-green-600 font-bold">Tersedia</span> di atas untuk mulai mengisi form.</p>
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Car, UsageLog } from '../types';
import { DEPARTMENTS, Icons } from '../constants';

interface Props {
  cars: Car[];
  onSubmit: (log: UsageLog) => void;
}

export default function FormPage({ cars, onSubmit }: Props) {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    carId: '',
    driverName: '',
    department: '',
    purpose: '',
    startOdometer: '',
    destination: '',
    notes: ''
  });

  const formRef = useRef<HTMLFormElement>(null);
  const selectedCar = cars.find(c => c.id === formData.carId);

  // Scroll to form automatically when car is selected
  useEffect(() => {
    if (formData.carId && formRef.current) {
      formRef.current.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }, [formData.carId]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCar || selectedCar.status !== 'available') {
      alert('Silakan pilih mobil yang tersedia terlebih dahulu.');
      return;
    }

    const newLog: UsageLog = {
      id: crypto.randomUUID(),
      carId: formData.carId,
      carName: `${selectedCar.name} (${selectedCar.plateNumber})`,
      driverName: formData.driverName,
      department: formData.department,
      purpose: formData.purpose,
      departureTime: new Date().toISOString(),
      startOdometer: parseInt(formData.startOdometer),
      destination: formData.destination,
      notes: formData.notes,
      status: 'active'
    };

    onSubmit(newLog);
    setSubmitted(true);
    setFormData({
      carId: '',
      driverName: '',
      department: '',
      purpose: '',
      startOdometer: '',
      destination: '',
      notes: ''
    });

    setTimeout(() => setSubmitted(false), 3000);
  };

  const handleCarSelect = (car: Car) => {
    if (car.status === 'available') {
      setFormData({ ...formData, carId: car.id });
    }
  };

  const resetSelection = () => {
    setFormData({ ...formData, carId: '' });
  };

  return (
    <div className="max-w-3xl mx-auto p-4 md:p-8 animate-in fade-in duration-500">
      <div className="mb-8">
        <h1 className="text-2xl md:text-3xl font-bold text-slate-900 mb-2">Pinjam Mobil Kantor</h1>
        <p className="text-slate-500 font-medium">Sistem monitoring otomatis HRGA FleetTrack.</p>
      </div>

      {submitted && (
        <div className="mb-8 p-5 bg-green-600 text-white rounded-2xl flex items-center gap-4 shadow-lg shadow-green-100 animate-in zoom-in duration-300">
          <div className="bg-white/20 p-2 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
          </div>
          <div>
            <p className="font-bold">Berhasil Disimpan!</p>
            <p className="text-sm opacity-90">Data perjalanan Anda sudah tercatat di sistem.</p>
          </div>
        </div>
      )}

      <div className="space-y-8">
        {/* SECTION: SELECTION GRID (Hidden when car is selected to focus on form) */}
        {!formData.carId ? (
          <div className="space-y-6">
            <div className="flex items-center gap-3">
              <span className="flex items-center justify-center w-8 h-8 bg-blue-600 text-white rounded-xl font-bold text-sm shadow-md shadow-blue-200">1</span>
              <h2 className="text-lg font-bold text-slate-800">Pilih Mobil Tersedia</h2>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {cars.map((car) => {
                const isAvailable = car.status === 'available';

                return (
                  <button
                    key={car.id}
                    disabled={!isAvailable}
                    onClick={() => handleCarSelect(car)}
                    className={`text-left group transition-all duration-300 rounded-3xl border-2 p-6 flex flex-col gap-4 relative overflow-hidden ${
                      isAvailable
                        ? 'border-slate-100 bg-white hover:border-blue-500 hover:shadow-xl hover:-translate-y-1 active:scale-95'
                        : 'border-slate-50 bg-slate-50/50 opacity-60 cursor-not-allowed grayscale'
                    }`}
                  >
                    {/* Background Accent */}
                    {isAvailable && (
                      <div className="absolute top-0 right-0 w-24 h-24 bg-blue-50 rounded-bl-full -mr-8 -mt-8 transition-transform group-hover:scale-110"></div>
                    )}

                    <div className="flex justify-between items-start relative z-10">
                      <div className={`p-4 rounded-2xl ${isAvailable ? 'bg-blue-50 text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors' : 'bg-slate-200 text-slate-400'}`}>
                        <Icons.Car />
                      </div>
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                        isAvailable ? 'bg-green-100 text-green-700' : 'bg-slate-200 text-slate-500'
                      }`}>
                        {isAvailable ? 'Tersedia' : car.status === 'in-use' ? 'Sedang Jalan' : 'Servis'}
                      </span>
                    </div>

                    <div className="relative z-10 mt-2">
                      <h3 className="font-bold text-xl text-slate-800 group-hover:text-blue-600 transition-colors">{car.name}</h3>
                      <p className="text-sm font-mono text-slate-500">{car.plateNumber}</p>
                    </div>

                    {isAvailable && (
                      <div className="mt-2 flex items-center gap-2 text-blue-600 font-bold text-xs">
                        Pilih Mobil Ini
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        ) : (
          /* SECTION: FOCUSED FORM (Visible after car is selected) */
          <div className="animate-in slide-in-from-bottom-6 duration-500">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <button 
                  onClick={resetSelection}
                  className="p-2 hover:bg-slate-100 rounded-full text-slate-500 transition-colors"
                  title="Ganti Mobil"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
                </button>
                <div className="flex items-center gap-3">
                  <span className="flex items-center justify-center w-8 h-8 bg-green-500 text-white rounded-xl font-bold text-sm shadow-md shadow-green-100">2</span>
                  <h2 className="text-lg font-bold text-slate-800">Detail Peminjaman</h2>
                </div>
              </div>
              <button 
                onClick={resetSelection}
                className="text-xs font-bold text-blue-600 hover:underline"
              >
                Ganti Mobil
              </button>
            </div>

            <form 
              ref={formRef}
              onSubmit={handleSubmit} 
              className="bg-white rounded-[2rem] border border-slate-200 shadow-2xl overflow-hidden"
            >
              {/* Car Highlight Banner */}
              <div className="bg-gradient-to-r from-blue-600 to-indigo-700 px-8 py-6 text-white flex items-center justify-between">
                <div className="flex items-center gap-5">
                  <div className="bg-white/20 p-4 rounded-2xl backdrop-blur-md">
                    <Icons.Car />
                  </div>
                  <div>
                    <p className="text-xs font-bold uppercase tracking-widest text-blue-100 mb-1">Mobil Terpilih</p>
                    <h3 className="text-2xl font-black">{selectedCar?.name}</h3>
                    <p className="text-sm font-mono opacity-80">{selectedCar?.plateNumber}</p>
                  </div>
                </div>
                <div className="hidden sm:block">
                  <div className="px-4 py-2 bg-white/10 rounded-xl border border-white/20 text-[10px] font-bold uppercase tracking-tighter">
                    Ready to go
                  </div>
                </div>
              </div>

              <div className="p-8 md:p-10 space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-3">
                    <label className="text-sm font-bold text-slate-600 flex items-center gap-2">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M19 21v-2a4 4 0 0 0-4-4H9a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
                      Nama Pengemudi
                    </label>
                    <input
                      type="text"
                      required
                      autoFocus
                      placeholder="Masukkan nama lengkap..."
                      value={formData.driverName}
                      onChange={e => setFormData({ ...formData, driverName: e.target.value })}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none bg-slate-50/50 transition-all font-medium text-slate-800 placeholder:text-slate-300"
                    />
                  </div>

                  <div className="space-y-3">
                    <label className="text-sm font-bold text-slate-600 flex items-center gap-2">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="18" x="3" y="3" rx="2"/><path d="M7 7h.01"/><path d="M17 7h.01"/><path d="M7 17h.01"/><path d="M17 17h.01"/></svg>
                      Departemen
                    </label>
                    <select
                      required
                      value={formData.department}
                      onChange={e => setFormData({ ...formData, department: e.target.value })}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none bg-slate-50/50 transition-all appearance-none font-medium text-slate-800 cursor-pointer"
                    >
                      <option value="">-- Pilih Departemen --</option>
                      {DEPARTMENTS.map(dept => (
                        <option key={dept} value={dept}>{dept}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-3">
                    <label className="text-sm font-bold text-slate-600 flex items-center gap-2">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
                      Odometer Awal (KM)
                    </label>
                    <input
                      type="number"
                      required
                      placeholder="Contoh: 12500"
                      value={formData.startOdometer}
                      onChange={e => setFormData({ ...formData, startOdometer: e.target.value })}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none bg-slate-50/50 transition-all font-mono font-bold text-blue-600"
                    />
                  </div>

                  <div className="space-y-3">
                    <label className="text-sm font-bold text-slate-600 flex items-center gap-2">
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>
                      Tujuan
                    </label>
                    <input
                      type="text"
                      required
                      placeholder="Lokasi tujuan..."
                      value={formData.destination}
                      onChange={e => setFormData({ ...formData, destination: e.target.value })}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none bg-slate-50/50 transition-all font-medium text-slate-800"
                    />
                  </div>
                </div>

                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-600 flex items-center gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
                    Alasan Perjalanan
                  </label>
                  <textarea
                    required
                    rows={2}
                    placeholder="Tuliskan keperluan operasional..."
                    value={formData.purpose}
                    onChange={e => setFormData({ ...formData, purpose: e.target.value })}
                    className="w-full px-5 py-4 rounded-2xl border-2 border-slate-100 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 outline-none bg-slate-50/50 transition-all resize-none font-medium text-slate-800"
                  />
                </div>
              </div>

              <div className="px-8 py-8 bg-slate-50 border-t border-slate-100">
                <button
                  type="submit"
                  className="w-full py-5 bg-slate-900 text-white font-black text-lg rounded-[1.5rem] hover:bg-blue-600 transition-all shadow-xl hover:shadow-blue-200 active:scale-[0.98] flex items-center justify-center gap-3"
                >
                  <Icons.Car />
                  KONFIRMASI KEBERANGKATAN
                </button>
                <p className="mt-4 text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                  Dengan mengklik, Anda bertanggung jawab penuh atas kendaraan ini.
                </p>
              </div>
            </form>
          </div>
        )}
      </div>

      {!formData.carId && (
        <div className="mt-16 text-center space-y-4">
          <div className="inline-flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-600 rounded-full text-xs font-bold animate-bounce">
            <Icons.Sparkles />
            Silakan pilih mobil di atas
          </div>
          <p className="text-slate-400 text-sm max-w-xs mx-auto">Sistem akan otomatis menampilkan form setelah Anda mengklik salah satu armada.</p>
        </div>
      )}
    </div>
  );
}

export interface Car {
  id: string;
  name: string;
  plateNumber: string;
  status: 'available' | 'on-duty' | 'maintenance';
}

export interface UsageLog {
  id: string;
  carId: string;
  carName: string;
  driverName: string;
  department: string;
  purpose: string;
  departureTime: string;
  arrivalTime?: string;
  startOdometer: number;
  endOdometer?: number;
  destination: string;
  notes?: string;
  status: 'active' | 'completed';
}

export interface AppState {
  cars: Car[];
  logs: UsageLog[];
}

