          </div>
        </div>
      </div>

      {completeDialog && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
          <div className="bg-white rounded-2xl p-6 w-full max-w-sm shadow-2xl">
            <h3 className="text-lg font-bold mb-2">Mobil Sudah Kembali?</h3>
            <p className="text-slate-500 text-sm mb-6">Masukkan angka odometer akhir untuk menyelesaikan peminjaman.</p>

            <div className="space-y-4 mb-6">
              <div>
                <label className="text-xs font-bold text-slate-500 block mb-1">Odometer Akhir (KM)</label>
                <input 
                  autoFocus
                  type="number" 
                  value={endOdo}
                  onChange={e => setEndOdo(e.target.value)}
                  placeholder="Misal: 12650"
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-mono"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setCompleteDialog(null)} className="py-2.5 text-slate-600 font-semibold hover:bg-slate-100 rounded-xl">Batal</button>
              <button onClick={() => handleFinish(completeDialog)} className="py-2.5 bg-blue-600 text-white font-semibold rounded-xl hover:bg-blue-700">Simpan & Selesai</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function StatCard({ label, value, color }: { label: string, value: number, color: string }) {
  return (
    <div className={`${color} rounded-2xl p-4 flex flex-col items-center justify-center shadow-sm`}>
      <span className="text-xs font-semibold opacity-70 mb-1">{label}</span>
      <span className="text-2xl font-bold">{value}</span>
    </div>
  );
}

