function StatCard({ label, value, color, accent }: { label: string, value: number, color: string, accent?: string }) {
  return (
    <div className={`${color} rounded-[2.5rem] p-8 border flex flex-col items-center justify-center relative overflow-hidden`}>
      {accent && <div className={`absolute top-0 left-0 w-1 h-full ${accent}`}></div>}
      <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-50 mb-3">{label}</span>
      <span className="text-5xl font-black tabular-nums">{value}</span>
    </div>
  );
}

export interface Car {
  id: string;
  name: string;
  plateNumber: string;
  status: 'available' | 'on-duty' | 'maintenance';
}

export type FuelLevel = 'E' | '1/4' | '1/2' | '3/4' | 'F';
export type VehicleCondition = 'BAIK' | 'PERLU PENGECEKAN';

export interface UsageLog {
  id: string;
  carId: string;
  carName: string;
  driverName: string;
  department: string;
  purpose: string;
  departureTime: string;
  arrivalTime?: string;
  startOdometer: number;
  endOdometer?: number;
  startFuel: FuelLevel;
  endFuel?: FuelLevel;
  startCondition: VehicleCondition;
  endCondition?: VehicleCondition;
  destination: string;
  notes?: string;
  status: 'active' | 'completed';
}

export interface AppState {
  cars: Car[];
  logs: UsageLog[];
}

import React, { useState, useRef, useEffect } from 'react';
import { Car, UsageLog, FuelLevel, VehicleCondition } from '../types';
import { DEPARTMENTS, Icons } from '../constants';

interface Props {
  cars: Car[];
  onSubmit: (log: UsageLog) => void;
}

export default function FormPage({ cars, onSubmit }: Props) {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    carId: '',
    driverName: '',
    department: '',
    purpose: '',
    startOdometer: '',
    startFuel: '1/2' as FuelLevel,
    startCondition: 'BAIK' as VehicleCondition,
    destination: '',
    notes: ''
  });

  const formRef = useRef<HTMLFormElement>(null);
  const selectedCar = cars.find(c => c.id === formData.carId);

  useEffect(() => {
    if (formData.carId && formRef.current) {
      formRef.current.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }, [formData.carId]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCar || selectedCar.status !== 'available') {
      alert('Kendaraan tidak tersedia.');
      return;
    }

    const newLog: UsageLog = {
      id: crypto.randomUUID(),
      carId: formData.carId,
      carName: `${selectedCar.name} (${selectedCar.plateNumber})`,
      driverName: formData.driverName,
      department: formData.department,
      purpose: formData.purpose,
      departureTime: new Date().toISOString(),
      startOdometer: parseInt(formData.startOdometer) || 0,
      startFuel: formData.startFuel,
      startCondition: formData.startCondition,
      destination: formData.destination,
      notes: formData.notes,
      status: 'active'
    };

    onSubmit(newLog);
    setSubmitted(true);
    setFormData({
      carId: '',
      driverName: '',
      department: '',
      purpose: '',
      startOdometer: '',
      startFuel: '1/2',
      startCondition: 'BAIK',
      destination: '',
      notes: ''
    });

    setTimeout(() => setSubmitted(false), 3000);
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-12 animate-in fade-in duration-700">
      <div className="mb-12">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-1 bg-fuchsia-600"></div>
