import React, { useState } from 'react';
import { Car, UsageLog, FuelLevel, VehicleCondition } from '../types';

interface Props {
  cars: Car[];
  logs: UsageLog[];
  onComplete: (id: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition }) => void;
}

export default function DashboardPage({ cars, logs, onComplete }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [completeDialog, setCompleteDialog] = useState<string | null>(null);
  const [endData, setEndData] = useState({
    endOdo: '',
    endFuel: '1/2' as FuelLevel,
    endCondition: 'BAIK' as VehicleCondition
  });

  const stats = {
    total: cars.length,
    available: cars.filter(c => c.status === 'available').length,
    onDuty: cars.filter(c => c.status === 'on-duty').length,
    maintenance: cars.filter(c => c.status === 'maintenance').length,
  };

  const handleFinish = (id: string) => {
    if (!endData.endOdo) return alert('Odometer akhir harus diisi');
    onComplete(id, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition
    });
    setCompleteDialog(null);
    setEndData({ endOdo: '', endFuel: '1/2', endCondition: 'BAIK' });
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

