import React, { useState, useRef, useEffect } from 'react';
import { Car, UsageLog, FuelLevel, VehicleCondition } from '../types';
import { DEPARTMENTS, Icons } from '../constants';

interface Props {
  cars: Car[];
  onSubmit: (log: UsageLog) => void;
}

export default function FormPage({ cars, onSubmit }: Props) {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    carId: '',
    driverName: '',
    department: '',
    purpose: '',
    departureTime: new Date().toISOString().slice(0, 16), // Format YYYY-MM-DDTHH:mm
    startOdometer: '',
    startFuel: '1/2' as FuelLevel,
    startCondition: 'BAIK' as VehicleCondition,
    destination: '',
    notes: ''
  });

  const formRef = useRef<HTMLFormElement>(null);
  const selectedCar = cars.find(c => c.id === formData.carId);

  useEffect(() => {
    if (formData.carId && formRef.current) {
      formRef.current.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }, [formData.carId]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCar || selectedCar.status !== 'available') {
      alert('Kendaraan tidak tersedia.');
      return;
    }

    const newLog: UsageLog = {
      id: crypto.randomUUID(),
      carId: formData.carId,
      carName: `${selectedCar.name} (${selectedCar.plateNumber})`,
      driverName: formData.driverName,
      department: formData.department,
      purpose: formData.purpose,
      departureTime: new Date(formData.departureTime).toISOString(),
      startOdometer: parseInt(formData.startOdometer) || 0,
      startFuel: formData.startFuel,
      startCondition: formData.startCondition,
      destination: formData.destination,
      notes: formData.notes,
      status: 'active'
    };

    onSubmit(newLog);
    setSubmitted(true);
    setFormData({
      carId: '',
      driverName: '',
      department: '',
      purpose: '',
      departureTime: new Date().toISOString().slice(0, 16),
      startOdometer: '',
      startFuel: '1/2',
      startCondition: 'BAIK',
      destination: '',
      notes: ''
    });

    setTimeout(() => setSubmitted(false), 3000);
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-12 animate-in fade-in duration-700">
      <div className="mb-12">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-1 bg-fuchsia-600"></div>
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Administrative Services</p>
        </div>
        <h1 className="text-3xl md:text-4xl font-black text-slate-950 uppercase tracking-tight leading-tight">Permohonan Penggunaan Kendaraan Operasional</h1>
      </div>

      {submitted && (
        <div className="mb-10 p-7 bg-fuchsia-600 text-white rounded-[2rem] flex items-center gap-5 shadow-2xl shadow-fuchsia-200 animate-in zoom-in duration-500">
          <div className="bg-white text-fuchsia-600 p-3 rounded-2xl shadow-inner">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
          </div>
          <div>
            <p className="font-black text-xl leading-none mb-1">REGISTRASI BERHASIL</p>
            <p className="text-sm opacity-90 font-bold uppercase tracking-tighter">Data telah terarsip secara elektronik di Fleet System.</p>
          </div>
        </div>
      )}

      {!formData.carId ? (
        <div className="space-y-8">
          <div className="flex items-center gap-4">
            <span className="flex items-center justify-center w-10 h-10 bg-slate-950 text-white rounded-2xl font-black text-xs border-b-4 border-fuchsia-600">01</span>
            <h2 className="text-lg font-black text-slate-900 uppercase tracking-widest">Pilih Unit Armada Tersedia</h2>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            {cars.map((car) => {
              const isAvailable = car.status === 'available';
              return (
                <button
                  key={car.id}
                  disabled={!isAvailable}
                  onClick={() => setFormData({...formData, carId: car.id})}
                  className={`text-left group transition-all duration-300 rounded-[2.5rem] border-2 p-8 flex flex-col gap-6 relative overflow-hidden ${
                    isAvailable ? 'border-slate-100 bg-white hover:border-fuchsia-500 hover:shadow-2xl hover:-translate-y-2' : 'border-slate-50 bg-slate-50/50 opacity-40 grayscale cursor-not-allowed'
                  }`}
                >
                  <div className="flex justify-between items-start relative z-10">
                    <div className={`p-5 rounded-3xl ${isAvailable ? 'bg-slate-950 text-white group-hover:bg-fuchsia-600' : 'bg-slate-200 text-slate-400'}`}>
                      <Icons.Car />
                    </div>
                    <span className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest ${car.status === 'available' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'}`}>
                      {car.status === 'available' ? 'Tersedia' : car.status}
                    </span>
                  </div>
                  <div className="relative z-10">
                    <h3 className="font-black text-2xl text-slate-950 group-hover:text-fuchsia-600 transition-colors">{car.name}</h3>
                    <p className="text-xs font-mono font-black text-slate-400 uppercase tracking-[0.2em] mt-1">{car.plateNumber}</p>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      ) : (
        <form ref={formRef} onSubmit={handleSubmit} className="bg-white rounded-[3rem] border border-slate-100 shadow-2xl overflow-hidden ring-1 ring-slate-100">
          <div className="bg-slate-950 px-12 py-10 text-white flex items-center justify-between relative overflow-hidden">
            <div className="absolute right-0 top-0 w-64 h-64 bg-fuchsia-600/10 rounded-full -mr-32 -mt-32"></div>
            <div className="flex items-center gap-8 relative z-10">
              <button type="button" onClick={() => setFormData({...formData, carId: ''})} className="p-4 bg-fuchsia-600 rounded-2xl hover:bg-fuchsia-700 transition-all">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
              </button>
              <div>
                <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-400 mb-2">Unit Terpilih</p>
                <h3 className="text-3xl font-black leading-none">{selectedCar?.name}</h3>
              </div>
            </div>
          </div>

          <div className="p-10 md:p-14 space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Pengemudi</label>
                <input type="text" required placeholder="NAMA LENGKAP" value={formData.driverName} onChange={e => setFormData({ ...formData, driverName: e.target.value })} className="w-full px-8 py-6 rounded-2xl border-2 border-slate-50 focus:border-fuchsia-500 outline-none bg-slate-50 font-black text-slate-950" />
              </div>
              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Departemen</label>
                <select required value={formData.department} onChange={e => setFormData({ ...formData, department: e.target.value })} className="w-full px-8 py-6 rounded-2xl border-2 border-slate-50 focus:border-fuchsia-500 outline-none bg-slate-50 font-black text-slate-950 appearance-none cursor-pointer">
                  <option value="">PILIH DEPARTEMEN</option>
                  {DEPARTMENTS.map(dept => <option key={dept} value={dept}>{dept}</option>)}
                </select>
              </div>
            </div>

            <div className="bg-slate-50/50 p-8 rounded-[2rem] border-2 border-dashed border-slate-200 space-y-10">
              <div className="flex items-center gap-3">
                <div className="w-1.5 h-4 bg-fuchsia-600 rounded-full"></div>
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Waktu & Verifikasi Teknis</h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tanggal & Jam Pinjam</label>
                  <input 
                    type="datetime-local" 
                    required 
                    value={formData.departureTime} 
                    onChange={e => setFormData({ ...formData, departureTime: e.target.value })} 
                    className="w-full px-8 py-6 rounded-2xl border-2 border-white focus:border-fuchsia-500 outline-none shadow-sm font-black text-slate-900 text-sm bg-white" 
                  />
                </div>
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Odometer Awal (KM)</label>
                  <input type="number" required placeholder="0" value={formData.startOdometer} onChange={e => setFormData({ ...formData, startOdometer: e.target.value })} className="w-full px-8 py-6 rounded-2xl border-2 border-white focus:border-fuchsia-500 outline-none shadow-sm font-mono font-black text-2xl text-fuchsia-600" />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Posisi Bahan Bakar</label>
                  <div className="flex gap-2">
                    {fuelOptions.map(option => (
                      <button
                        key={option}
                        type="button"
                        onClick={() => setFormData({...formData, startFuel: option})}
                        className={`flex-1 py-4 rounded-xl font-black text-xs transition-all border-2 ${formData.startFuel === option ? 'bg-slate-950 text-white border-slate-950 shadow-lg' : 'bg-white text-slate-400 border-slate-100 hover:border-fuchsia-200'}`}
                      >
                        {option}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Kondisi Fisik</label>
                  <div className="flex gap-2">
                    <button
                      type="button"
                      onClick={() => setFormData({...formData, startCondition: 'BAIK'})}
                      className={`flex-1 py-4 rounded-xl font-black text-[10px] transition-all border-2 ${formData.startCondition === 'BAIK' ? 'bg-green-600 text-white border-green-700 shadow-md' : 'bg-white text-slate-400 border-slate-100'}`}
                    >
                      BAIK
                    </button>
                    <button
                      type="button"
                      onClick={() => setFormData({...formData, startCondition: 'PERLU PENGECEKAN'})}
                      className={`flex-1 py-4 rounded-xl font-black text-[10px] transition-all border-2 ${formData.startCondition === 'PERLU PENGECEKAN' ? 'bg-amber-500 text-white border-amber-600 shadow-md' : 'bg-white text-slate-400 border-slate-100'}`}
                    >
                      KENDALA
                    </button>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Destinasi & Keperluan</label>
              <input type="text" required placeholder="TUJUAN" value={formData.destination} onChange={e => setFormData({ ...formData, destination: e.target.value })} className="w-full px-8 py-6 rounded-2xl border-2 border-slate-50 focus:border-fuchsia-500 outline-none bg-slate-50 font-black text-slate-950 mb-4" />
              <textarea required rows={3} placeholder="TUJUAN & AGENDA" value={formData.purpose} onChange={e => setFormData({ ...formData, purpose: e.target.value })} className="w-full px-8 py-6 rounded-2xl border-2 border-slate-50 focus:border-fuchsia-500 outline-none bg-slate-50 font-black text-slate-950 resize-none" />
            </div>
          </div>

          <div className="px-12 py-12 bg-slate-50 border-t border-slate-100 flex justify-end">
            <button type="submit" className="w-full md:w-auto px-16 py-7 bg-slate-950 text-white font-black text-sm rounded-[2rem] hover:bg-fuchsia-600 transition-all shadow-2xl active:scale-95 flex items-center justify-center gap-4 uppercase tracking-[0.2em]">
              <Icons.Car />
              Konfirmasi Registrasi
            </button>
          </div>
        </form>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Car, UsageLog, FuelLevel, VehicleCondition } from '../types';

interface Props {
  cars: Car[];
  logs: UsageLog[];
  onComplete: (id: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => void;
}

export default function DashboardPage({ cars, logs, onComplete }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [completeDialog, setCompleteDialog] = useState<string | null>(null);
  const [endData, setEndData] = useState({
    endOdo: '',
    endFuel: '1/2' as FuelLevel,
    endCondition: 'BAIK' as VehicleCondition,
    arrivalTime: new Date().toISOString().slice(0, 16) // Default to now
  });

  const stats = {
    total: cars.length,
    available: cars.filter(c => c.status === 'available').length,
    onDuty: cars.filter(c => c.status === 'on-duty').length,
    maintenance: cars.filter(c => c.status === 'maintenance').length,
  };

  const handleFinish = (id: string) => {
    if (!endData.endOdo) return alert('Odometer akhir harus diisi');
    onComplete(id, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition,
      arrivalTime: new Date(endData.arrivalTime).toISOString()
    });
    setCompleteDialog(null);
    setEndData({ endOdo: '', endFuel: '1/2', endCondition: 'BAIK', arrivalTime: new Date().toISOString().slice(0, 16) });
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="p-4 md:p-12 space-y-12 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-slate-200 pb-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-1 bg-fuchsia-600"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Fleet Operations</p>
          </div>
          <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tight">Monitoring Armada Real-Time</h1>
        </div>
        <div className="flex items-center gap-3 px-6 py-3 bg-white shadow-sm rounded-2xl border border-slate-100 text-[10px] font-black text-slate-500 uppercase tracking-widest">
          <span className="w-2 h-2 bg-fuchsia-600 rounded-full animate-ping"></span>
          Live Fleet Synchronization
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-8">
        <StatCard label="Total Armada" value={stats.total} color="bg-slate-950 text-white shadow-2xl shadow-slate-200" />
        <StatCard label="Siap Pakai" value={stats.available} color="bg-white border-slate-100 text-slate-900" accent="bg-green-500" />
        <StatCard label="On Duty" value={stats.onDuty} color="bg-white border-slate-100 text-slate-900" accent="bg-fuchsia-600" />
        <StatCard label="Service" value={stats.maintenance} color="bg-white border-slate-100 text-slate-900" accent="bg-amber-500" />
