          </div>

          {activeLogs.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center">
              <p className="text-slate-400 font-black uppercase text-xs tracking-[0.2em]">Seluruh unit berada di pool keberangkatan.</p>
