  );
}

import React, { useState, useEffect } from 'react';
import { Car, UsageLog, FuelLevel, VehicleCondition } from '../types';

interface Props {
  cars: Car[];
  logs: UsageLog[];
  onComplete: (id: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => void;
}

export default function DashboardPage({ cars, logs, onComplete }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [completeDialog, setCompleteDialog] = useState<string | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());

  const [endData, setEndData] = useState({
    endOdo: '',
    endFuel: '1/2' as FuelLevel,
    endCondition: 'BAIK' as VehicleCondition,
    arrivalTime: new Date().toISOString().slice(0, 16)
  });

  // Update current time every minute for overdue check
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const stats = {
    total: cars.length,
    available: cars.filter(c => c.status === 'available').length,
    onDuty: cars.filter(c => c.status === 'on-duty').length,
    maintenance: cars.filter(c => c.status === 'maintenance').length,
  };

  const handleFinish = (id: string) => {
    if (!endData.endOdo) return alert('Odometer akhir wajib diisi untuk laporan HRGA.');
    onComplete(id, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition,
      arrivalTime: new Date(endData.arrivalTime).toISOString()
    });
    setCompleteDialog(null);
    setEndData({ endOdo: '', endFuel: '1/2', endCondition: 'BAIK', arrivalTime: new Date().toISOString().slice(0, 16) });
  };

  const getDelayInfo = (estimatedStr: string) => {
    const est = new Date(estimatedStr);
    const diff = currentTime.getTime() - est.getTime();
    if (diff <= 0) return null;

    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(minutes / 60);
    const remainingMins = minutes % 60;

    return hours > 0 ? `${hours} jam ${remainingMins} menit` : `${minutes} menit`;
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="p-4 md:p-12 space-y-12 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-slate-200 pb-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-1 bg-fuchsia-600"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Fleet Operations Control</p>
          </div>
          <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tight">Monitoring Armada Real-Time</h1>
        </div>
        <div className="flex items-center gap-3 px-6 py-3 bg-white shadow-sm rounded-2xl border border-slate-100 text-[10px] font-black text-slate-500 uppercase tracking-widest">
          <span className="w-2 h-2 bg-fuchsia-600 rounded-full animate-ping"></span>
          Live Update: {currentTime.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-8">
        <StatCard label="Total Armada" value={stats.total} color="bg-slate-950 text-white shadow-2xl shadow-slate-200" />
        <StatCard label="Siap Pakai" value={stats.available} color="bg-white border-slate-100 text-slate-900" accent="bg-green-500" />
        <StatCard label="Sedang Jalan" value={stats.onDuty} color="bg-white border-slate-100 text-slate-900" accent="bg-fuchsia-600" />
        <StatCard label="Dalam Perbaikan" value={stats.maintenance} color="bg-white border-slate-100 text-slate-900" accent="bg-amber-500" />
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-12">
        <div className="xl:col-span-2 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-2 h-8 bg-fuchsia-600 rounded-full"></div>
            <h2 className="text-xl font-black text-slate-950 uppercase tracking-wider">Aktivitas Berjalan ({activeLogs.length})</h2>
          </div>

          {activeLogs.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center">
              <p className="text-slate-400 font-black uppercase text-xs tracking-[0.2em]">Seluruh unit berada di pool. Tidak ada perjalanan aktif.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {activeLogs.map(log => {
                const delay = getDelayInfo(log.estimatedArrivalTime);
                return (
                  <div key={log.id} className={`bg-white rounded-[2.5rem] border p-8 shadow-2xl transition-all group relative overflow-hidden ${delay ? 'border-red-500 ring-4 ring-red-50' : 'border-slate-50 shadow-slate-200/40'}`}>
                    {delay && (
                      <div className="absolute top-0 right-0 bg-red-600 text-white px-6 py-2 rounded-bl-3xl animate-pulse z-20">
                        <p className="text-[10px] font-black uppercase tracking-widest text-center">OVERDUE</p>
                      </div>
                    )}

                    <div className="flex justify-between items-start mb-6">
                      <div>
                        <h3 className="font-black text-2xl text-slate-950 group-hover:text-fuchsia-600 transition-colors">{log.carName}</h3>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{log.driverName} • {log.department}</p>
                      </div>
                    </div>

                    <div className={`${delay ? 'bg-red-50 border-red-100' : 'bg-slate-50 border-slate-100'} rounded-2xl p-5 mb-8 flex justify-between items-center border transition-colors`}>
                      <div>
                        <p className={`text-[8px] font-black uppercase tracking-widest mb-1 ${delay ? 'text-red-600' : 'text-slate-400'}`}>
                          {delay ? 'Terlambat Selama' : 'Estimasi Kembali'}
                        </p>
                        <p className={`font-black text-sm ${delay ? 'text-red-700' : 'text-slate-950'}`}>
                          {delay ? delay : new Date(log.estimatedArrivalTime).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }) + ' WIB'}
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Destinasi</p>
                        <p className="font-black text-sm text-slate-950 truncate max-w-[120px]">{log.destination}</p>
                      </div>
                    </div>

                    <div className="flex flex-col gap-3">
                      <button 
                        onClick={() => {
                          setEndData(prev => ({ ...prev, arrivalTime: new Date().toISOString().slice(0, 16) }));
                          setCompleteDialog(log.id);
                        }}
                        className={`w-full py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all shadow-lg flex items-center justify-center gap-2 ${delay ? 'bg-red-600 hover:bg-red-700' : 'bg-slate-950 hover:bg-fuchsia-600'} text-white`}
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6 9 17l-5-5"/></svg>
                        Selesaikan Tugas
                      </button>

                      {delay && (
                        <a 
                          href={`tel:08123456789`} // Mock contact
                          className="text-center py-2 text-red-600 font-black text-[9px] uppercase tracking-widest hover:underline animate-bounce"
                        >
                          ⚠️ Hubungi Driver Segera
                        </a>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        <div className="bg-white border border-slate-100 rounded-[3rem] p-10 h-fit shadow-xl shadow-slate-200/50">
          <h2 className="font-black text-slate-950 uppercase text-[10px] tracking-[0.3em] mb-8 pb-4 border-b border-slate-50 text-center">Status Keseluruhan Unit</h2>
          <div className="space-y-6">
            {cars.map(car => (
              <div key={car.id} className="flex items-center justify-between p-5 rounded-2xl hover:bg-slate-50 transition-all group">
                <div className="flex items-center gap-4">
                  <div className={`w-3 h-3 rounded-full border-2 border-white ${car.status === 'available' ? 'bg-green-500' : car.status === 'on-duty' ? 'bg-fuchsia-600' : 'bg-amber-500'}`}></div>
                  <div>
                    <p className="font-black text-sm text-slate-950 leading-none mb-1 group-hover:text-fuchsia-600 transition-colors">{car.name}</p>
                    <p className="text-[10px] text-slate-400 font-mono font-bold tracking-tighter">{car.plateNumber}</p>
                  </div>
                </div>
                <span className={`text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-widest ${car.status === 'available' ? 'bg-green-50 text-green-600' : 'bg-slate-50 text-slate-400'}`}>
                  {car.status}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {completeDialog && (
        <div className="fixed inset-0 bg-slate-950/60 backdrop-blur-xl flex items-center justify-center p-6 z-[100] animate-in fade-in duration-500">
          <div className="bg-white rounded-[3rem] p-10 w-full max-w-md shadow-2xl border border-white/20 overflow-y-auto max-h-[90vh]">
            <div className="mb-8 text-center">
              <div className="w-16 h-1 bg-fuchsia-600 mx-auto mb-4"></div>
              <h3 className="text-2xl font-black text-slate-950 uppercase tracking-tight mb-2">Penyelesaian Tugas</h3>
              <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest opacity-60">Verifikasi data unit setelah pemakaian</p>
            </div>

            <div className="space-y-6 mb-10">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-center">Jam Kembali Aktual</label>
                <input 
                  type="datetime-local" 
                  value={endData.arrivalTime}
                  onChange={e => setEndData({ ...endData, arrivalTime: e.target.value })}
                  className="w-full px-6 py-4 border-2 border-slate-50 rounded-2xl outline-none focus:border-fuchsia-500 font-black text-sm text-center text-slate-950 bg-slate-50"
                />
              </div>

              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-center">Odometer Akhir (KM)</label>
                <input 
                  autoFocus
                  type="number" 
                  value={endData.endOdo}
                  onChange={e => setEndData({ ...endData, endOdo: e.target.value })}
                  placeholder="Input KM Terakhir"
                  className="w-full px-8 py-6 border-2 border-slate-50 rounded-[2rem] outline-none focus:border-fuchsia-500 font-mono font-black text-3xl text-center text-slate-950 bg-slate-50"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-center">Fuel Akhir</label>
                  <select 
                    value={endData.endFuel}
                    onChange={e => setEndData({ ...endData, endFuel: e.target.value as FuelLevel })}
                    className="w-full p-4 border-2 border-slate-50 rounded-xl font-black text-xs text-center bg-slate-50 outline-none focus:border-fuchsia-500"
                  >
                    {fuelOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-center">Kondisi Fisik</label>
                  <select 
                    value={endData.endCondition}
                    onChange={e => setEndData({ ...endData, endCondition: e.target.value as VehicleCondition })}
                    className="w-full p-4 border-2 border-slate-50 rounded-xl font-black text-[10px] text-center bg-slate-50 outline-none focus:border-fuchsia-500"
                  >
                    <option value="BAIK">BAIK & BERSIH</option>
                    <option value="PERLU PENGECEKAN">KOTOR / RUSAK</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-4">
              <button onClick={() => handleFinish(completeDialog)} className="py-6 bg-slate-950 text-white font-black uppercase text-xs tracking-[0.3em] rounded-3xl hover:bg-fuchsia-600 shadow-2xl transition-all active:scale-95">Verify & Ready to Use</button>
              <button onClick={() => setCompleteDialog(null)} className="py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-slate-600 transition-all text-center">Batalkan</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function StatCard({ label, value, color, accent }: { label: string, value: number, color: string, accent?: string }) {
  return (
    <div className={`${color} rounded-[2.5rem] p-8 border border-slate-100 flex flex-col items-center justify-center relative overflow-hidden shadow-sm transition-transform hover:scale-105`}>
      {accent && <div className={`absolute top-0 left-0 w-1.5 h-full ${accent}`}></div>}
      <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-50 mb-3 text-center leading-tight">{label}</span>
      <span className="text-5xl font-black tabular-nums">{value}</span>
    </div>
  );
}

import React, { useState } from 'react';
import { UsageLog } from '../types';

interface Props {
  logs: UsageLog[];
}

export default function HistoryPage({ logs }: Props) {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredLogs = logs.filter(log => 
    log.driverName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.carName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const formatDate = (dateStr: string) => {
    return new Intl.DateTimeFormat('id-ID', {
      day: 'numeric',
      month: 'short',
      year: 'numeric'
    }).format(new Date(dateStr));
  };

  const formatTime = (dateStr: string) => {
    return new Intl.DateTimeFormat('id-ID', {
      hour: '2-digit',
      minute: '2-digit'
    }).format(new Date(dateStr));
  };

  const checkLate = (est: string, act?: string) => {
    if (!act) return false;
    return new Date(act) > new Date(est);
  };

  return (
    <div className="p-4 md:p-12 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-1 bg-fuchsia-600"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Archived Records</p>
          </div>
          <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tight">Log Aktivitas Operasional</h1>
        </div>

        <div className="relative w-full md:w-[400px]">
          <input
            type="text"
            placeholder="Cari Driver atau Unit..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="w-full pl-16 pr-8 py-5 bg-white border border-slate-100 rounded-[2rem] focus:border-fuchsia-500 outline-none transition-all font-black text-sm shadow-sm ring-1 ring-slate-50 placeholder:text-slate-200"
          />
          <div className="absolute left-6 top-1/2 -translate-y-1/2 text-fuchsia-600">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-2xl shadow-slate-200/50 overflow-hidden ring-1 ring-slate-50">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead>
              <tr className="bg-slate-950 text-white">
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900">User & Armada</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900">Tujuan</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900 text-center">Waktu Berangkat</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900 text-center">Estimasi vs Aktual</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900 text-center">Logistik</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em]">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredLogs.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-10 py-32 text-center text-slate-300 font-black uppercase text-xs tracking-[0.3em]">Belum ada catatan operasional.</td>
                </tr>
              ) : (
                filteredLogs.map(log => {
                  const isLate = checkLate(log.estimatedArrivalTime, log.arrivalTime);
                  return (
                    <tr key={log.id} className={`hover:bg-fuchsia-50/30 transition-colors group ${isLate ? 'bg-red-50/20' : ''}`}>
                      <td className="px-8 py-8">
                        <p className="font-black text-slate-950 text-lg group-hover:text-fuchsia-600 transition-colors leading-none mb-1">{log.driverName}</p>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{log.carName} • {log.department}</p>
                      </td>
                      <td className="px-8 py-8">
                        <p className="text-sm font-black text-slate-700 leading-tight mb-2">{log.destination}</p>
                        <p className="text-[9px] text-slate-400 font-bold italic truncate max-w-[150px]">"{log.purpose}"</p>
                      </td>
                      <td className="px-8 py-8 text-center border-r border-slate-50">
                        <p className="text-xs font-black text-slate-950">{formatDate(log.departureTime)}</p>
                        <p className="text-[10px] font-bold text-fuchsia-600">{formatTime(log.departureTime)} WIB</p>
                      </td>
                      <td className="px-8 py-8 text-center border-r border-slate-50">
                        <div className="flex flex-col gap-1 items-center">
                          <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">EST: {formatTime(log.estimatedArrivalTime)}</span>
                          {log.arrivalTime ? (
                            <p className={`text-xs font-black ${isLate ? 'text-red-600 underline decoration-2' : 'text-slate-950'}`}>
                              AKTUAL: {formatTime(log.arrivalTime)}
                            </p>
                          ) : (
                            <span className="text-[9px] font-black text-fuchsia-600 animate-pulse uppercase">OTW...</span>
                          )}
                        </div>
                      </td>
                      <td className="px-8 py-8">
                        <div className="flex flex-col gap-2">
                           <div className="flex gap-2">
                             <span className="text-[8px] font-black px-2 py-0.5 bg-slate-950 text-white rounded">BBM: {log.endFuel || log.startFuel}</span>
                             <span className={`text-[8px] font-black px-2 py-0.5 rounded ${log.endCondition === 'BAIK' ? 'bg-green-100 text-green-700' : log.status === 'active' ? 'bg-slate-100 text-slate-400' : 'bg-amber-100 text-amber-700'}`}>
                               {log.endCondition || 'CHECKING'}
                             </span>
                           </div>
                           <div className="font-mono text-[9px] font-black text-slate-400">
                             {log.endOdometer ? `DIST: ${log.endOdometer - log.startOdometer} KM` : `ODO: ${log.startOdometer} KM`}
                           </div>
                        </div>
                      </td>
                      <td className="px-8 py-8">
                        <span className={`inline-flex px-4 py-2 rounded-full text-[9px] font-black uppercase tracking-[0.2em] border ${
                          log.status === 'active' ? 'bg-fuchsia-600 text-white border-fuchsia-500 shadow-lg' : isLate ? 'bg-red-600 text-white border-red-500' : 'bg-slate-50 text-slate-400 border-slate-100'
                        }`}>
                          {log.status === 'active' ? 'On Trip' : isLate ? 'Late Return' : 'Returned'}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Car, UsageLog, FuelLevel, VehicleCondition } from '../types';

interface Props {
  cars: Car[];
  logs: UsageLog[];
  onComplete: (id: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => void;
}

export default function DashboardPage({ cars, logs, onComplete }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [completeDialog, setCompleteDialog] = useState<string | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());

  const [endData, setEndData] = useState({
    endOdo: '',
    endFuel: '1/2' as FuelLevel,
    endCondition: 'BAIK' as VehicleCondition,
    arrivalTime: new Date().toISOString().slice(0, 16)
  });

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const stats = {
    total: cars.length,
    available: cars.filter(c => c.status === 'available').length,
    onDuty: cars.filter(c => c.status === 'on-duty').length,
    maintenance: cars.filter(c => c.status === 'maintenance').length,
    overdue: activeLogs.filter(l => new Date() > new Date(l.estimatedArrivalTime)).length
  };

  const handleFinish = (id: string) => {
    if (!endData.endOdo) return alert('Odometer akhir wajib diisi untuk validasi HRGA.');
    onComplete(id, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition,
      arrivalTime: new Date(endData.arrivalTime).toISOString()
    });
    setCompleteDialog(null);
    setEndData({ endOdo: '', endFuel: '1/2', endCondition: 'BAIK', arrivalTime: new Date().toISOString().slice(0, 16) });
  };

  const getDelayInfo = (estimatedStr: string) => {
    const est = new Date(estimatedStr);
    const diff = currentTime.getTime() - est.getTime();
    if (diff <= 0) return null;

    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(minutes / 60);
    const remainingMins = minutes % 60;

    return hours > 0 ? `${hours} jam ${remainingMins} menit` : `${minutes} menit`;
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="p-4 md:p-12 space-y-12 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-slate-200 pb-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-1 bg-fuchsia-600"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Fleet Operations Control</p>
          </div>
          <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tight">Monitoring Armada Real-Time</h1>
        </div>
        <div className="flex items-center gap-3 px-6 py-3 bg-white shadow-sm rounded-2xl border border-slate-100 text-[10px] font-black text-slate-500 uppercase tracking-widest">
          <span className="w-2 h-2 bg-fuchsia-600 rounded-full animate-ping"></span>
          Live Sync: {currentTime.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })}
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-5 gap-6">
        <StatCard label="Total Unit" value={stats.total} color="bg-slate-950 text-white shadow-2xl" />
        <StatCard label="Ready" value={stats.available} color="bg-white border-slate-100" accent="bg-green-500" />
        <StatCard label="On Trip" value={stats.onDuty} color="bg-white border-slate-100" accent="bg-fuchsia-600" />
        <StatCard label="Telat" value={stats.overdue} color={stats.overdue > 0 ? "bg-red-600 text-white animate-pulse shadow-red-200 shadow-xl" : "bg-white border-slate-100 text-slate-300"} />
        <StatCard label="Service" value={stats.maintenance} color="bg-white border-slate-100" accent="bg-amber-500" />
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-12">
        <div className="xl:col-span-2 space-y-8">
          <div className="flex items-center gap-4">
            <div className="w-2 h-8 bg-fuchsia-600 rounded-full"></div>
            <h2 className="text-xl font-black text-slate-950 uppercase tracking-wider">Aktivitas Berjalan ({activeLogs.length})</h2>
          </div>

          {activeLogs.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center">
              <p className="text-slate-400 font-black uppercase text-xs tracking-[0.2em]">Seluruh unit berada di pool.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {activeLogs.map(log => {
                const delay = getDelayInfo(log.estimatedArrivalTime);
                return (
                  <div key={log.id} className={`bg-white rounded-[2.5rem] border p-8 shadow-2xl transition-all group relative overflow-hidden ${delay ? 'border-red-500 ring-4 ring-red-50' : 'border-slate-50 shadow-slate-200/40'}`}>
                    {delay && (
                      <div className="absolute top-0 right-0 bg-red-600 text-white px-6 py-2 rounded-bl-3xl z-20">
                        <p className="text-[10px] font-black uppercase tracking-widest text-center">LATE</p>
                      </div>
                    )}

                    <div className="flex justify-between items-start mb-6">
                      <div>
                        <h3 className="font-black text-2xl text-slate-950 group-hover:text-fuchsia-600 transition-colors leading-none mb-1">{log.carName}</h3>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{log.driverName} • {log.department}</p>
                      </div>
                    </div>

                    <div className={`${delay ? 'bg-red-50 border-red-100' : 'bg-slate-50 border-slate-100'} rounded-2xl p-5 mb-8 flex justify-between items-center border transition-colors`}>
                      <div>
                        <p className={`text-[8px] font-black uppercase tracking-widest mb-1 ${delay ? 'text-red-600' : 'text-slate-400'}`}>
                          {delay ? 'Keterlambatan' : 'Estimasi Kembali'}
                        </p>
                        <p className={`font-black text-sm ${delay ? 'text-red-700' : 'text-slate-950'}`}>
                          {delay ? delay : new Date(log.estimatedArrivalTime).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }) + ' WIB'}
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Tujuan</p>
                        <p className="font-black text-sm text-slate-950 truncate max-w-[120px]">{log.destination}</p>
                      </div>
                    </div>

                    <div className="flex flex-col gap-3">
                      <button 
                        onClick={() => {
                          setEndData(prev => ({ ...prev, arrivalTime: new Date().toISOString().slice(0, 16) }));
                          setCompleteDialog(log.id);
                        }}
                        className={`w-full py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all shadow-lg flex items-center justify-center gap-2 ${delay ? 'bg-red-600 hover:bg-red-700' : 'bg-slate-950 hover:bg-fuchsia-600'} text-white`}
                      >
                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6 9 17l-5-5"/></svg>
                        Selesaikan Tugas
