export default function App() {
  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('fleet_cars', JSON.stringify(cars));
  }, [cars]);

  useEffect(() => {
    localStorage.setItem('fleet_logs', JSON.stringify(logs));
  }, [logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs([newLog, ...logs]);
    setCars(prev => prev.map(c => 
      c.id === newLog.carId ? { ...c, status: 'on-duty' } : c
    ));
  };

  const completeLog = (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;

    setLogs(prev => prev.map(l => 
      l.id === logId 
        ? { 
            ...l, 
            status: 'completed' as const, 
            endOdometer: endData.endOdo, 
            endFuel: endData.endFuel,
            endCondition: endData.endCondition,
            arrivalTime: endData.arrivalTime 
          } 
        : l
    ));

    setCars(prev => prev.map(c => 
      c.id === logToFinish.carId ? { ...c, status: 'available' } : c
    ));
  };

  return (
    <HashRouter>
      <div className="flex min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar />
        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} />} />
            <Route path="/dashboard" element={<DashboardPage cars={cars} logs={logs} onComplete={completeLog} />} />
            <Route path="/history" element={<HistoryPage logs={logs} />} />
          </Routes>
        </main>
        <BottomNav />
      </div>
    </HashRouter>
  );
}

import React, { useState } from 'react';
import { UsageLog, FuelLevel, VehicleCondition } from '../types';
import { Icons } from '../constants';

interface Props {
  logs: UsageLog[];
  onComplete: (id: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => void;
}

export default function ReturnPage({ logs, onComplete }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [selectedLogId, setSelectedLogId] = useState<string | null>(null);
  const [submitted, setSubmitted] = useState(false);

  const [endData, setEndData] = useState({
    endOdo: '',
    endFuel: '1/2' as FuelLevel,
    endCondition: 'BAIK' as VehicleCondition,
    arrivalTime: new Date().toISOString().slice(0, 16)
  });

  const selectedLog = logs.find(l => l.id === selectedLogId);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedLogId || !endData.endOdo) return;

    onComplete(selectedLogId, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition,
      arrivalTime: new Date(endData.arrivalTime).toISOString()
    });

    setSubmitted(true);
    setSelectedLogId(null);
    setEndData({
      endOdo: '',
      endFuel: '1/2',
      endCondition: 'BAIK',
      arrivalTime: new Date().toISOString().slice(0, 16)
    });

    setTimeout(() => setSubmitted(false), 3000);
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-12 animate-in fade-in duration-700">
      <div className="mb-12">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-1 bg-fuchsia-600"></div>
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Fleet Arrival Registry</p>
        </div>
        <h1 className="text-3xl md:text-4xl font-black text-slate-950 uppercase tracking-tight leading-tight">Konfirmasi Pengembalian Unit</h1>
        <p className="text-slate-500 font-bold text-xs uppercase tracking-widest mt-2">Pilih unit yang baru saja Anda parkirkan</p>
      </div>

      {submitted && (
        <div className="mb-10 p-7 bg-green-600 text-white rounded-[2rem] flex items-center gap-5 shadow-2xl animate-in zoom-in duration-500">
          <div className="bg-white text-green-600 p-3 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
          </div>
          <div>
            <p className="font-black text-xl leading-none mb-1">UNIT TELAH KEMBALI</p>
            <p className="text-sm opacity-90 font-bold uppercase tracking-tighter">Status armada sudah "Available" di pool.</p>
          </div>
        </div>
      )}

      {!selectedLogId ? (
        <div className="space-y-6">
          {activeLogs.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center">
              <p className="text-slate-400 font-black uppercase text-xs tracking-[0.2em]">Tidak ada unit yang sedang bertugas.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {activeLogs.map(log => (
                <button
                  key={log.id}
                  onClick={() => setSelectedLogId(log.id)}
                  className="text-left bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-xl hover:shadow-2xl hover:border-fuchsia-500 hover:-translate-y-1 transition-all group"
                >
                  <div className="flex justify-between items-start mb-6">
                    <div className="p-4 bg-slate-950 text-white rounded-2xl group-hover:bg-fuchsia-600 transition-colors">
                      <Icons.Car />
                    </div>
                    <span className="text-[9px] font-black px-3 py-1 bg-fuchsia-100 text-fuchsia-600 rounded-full uppercase tracking-widest">On Duty</span>
                  </div>
                  <h3 className="text-xl font-black text-slate-950 leading-none mb-1">{log.carName}</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{log.driverName} • {log.department}</p>
                </button>
              ))}
            </div>
          )}
        </div>
