                  </button>
                </div>
                <p className="text-[8px] font-bold text-slate-400 italic leading-tight">*(Pilih 'Perlu Pengecekan' jika unit kotor, lecet, atau ada kendala lainnya)*</p>
              </div>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Waktu Sampai Aktual</label>
              <input 
                type="datetime-local" 
                required
                value={endData.arrivalTime}
                onChange={e => setEndData({ ...endData, arrivalTime: e.target.value })}
                className="w-full px-8 py-6 rounded-2xl border-2 border-slate-50 focus:border-fuchsia-500 outline-none bg-slate-50 font-black text-slate-900"
              />
            </div>
          </div>

          <div className="p-10 bg-slate-50 border-t border-slate-100">
             <button type="submit" className="w-full py-8 bg-slate-950 text-white font-black uppercase text-sm tracking-[0.3em] rounded-[2rem] hover:bg-fuchsia-600 transition-all shadow-2xl active:scale-95 flex items-center justify-center gap-4">
                <Icons.Return />
                Konfirmasi Unit Sampai
             </button>
          </div>
        </form>
      )}

      {/* Modal Extend */}
      {extendLogId && (
        <div className="fixed inset-0 bg-slate-950/60 backdrop-blur-xl flex items-center justify-center p-6 z-[100] animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 w-full max-w-md shadow-2xl border border-white/20">
            <div className="mb-8 text-center">
              <div className="w-16 h-1 bg-fuchsia-600 mx-auto mb-4"></div>
              <h3 className="text-2xl font-black text-slate-950 uppercase tracking-tight mb-2">Perpanjang Waktu</h3>
              <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest opacity-60">Informasikan jadwal baru ke HRGA</p>
            </div>

            <form onSubmit={handleExtend} className="space-y-6">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-center">Estimasi Kembali Baru</label>
                <input 
                  type="datetime-local" 
                  required
                  value={extendData.newTime}
                  onChange={e => setExtendData({ ...extendData, newTime: e.target.value })}
                  className="w-full px-6 py-5 border-2 border-slate-50 rounded-2xl outline-none focus:border-fuchsia-500 font-black text-sm text-center text-slate-950 bg-slate-50"
                />
              </div>

              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-center">Alasan Perpanjangan</label>
                <textarea 
                  required
                  placeholder="Contoh: Macet, ada tambahan agenda..."
                  value={extendData.reason}
                  onChange={e => setExtendData({ ...extendData, reason: e.target.value })}
                  className="w-full px-6 py-4 border-2 border-slate-50 rounded-2xl outline-none focus:border-fuchsia-500 font-bold text-xs text-slate-900 bg-slate-50 resize-none h-24"
                />
              </div>

              <div className="flex flex-col gap-4 mt-10">
                <button type="submit" className="py-6 bg-slate-950 text-white font-black uppercase text-xs tracking-[0.3em] rounded-3xl hover:bg-fuchsia-600 shadow-2xl transition-all active:scale-95">Update Estimasi</button>
                <button type="button" onClick={() => setExtendLogId(null)} className="py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-slate-600 transition-all text-center">Batalkan</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

