import React, { useState, useRef } from 'react';
import { UsageLog } from '../types';

interface Props {
  logs: UsageLog[];
}

export default function HistoryPage({ logs }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filteredLogs = logs.filter(log => 
    log.driverName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.carName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const formatDate = (dateStr: string) => {
    return new Intl.DateTimeFormat('id-ID', {
      day: 'numeric',
      month: 'short',
      year: 'numeric'
    }).format(new Date(dateStr));
  };

  const formatTime = (dateStr: string) => {
    return new Intl.DateTimeFormat('id-ID', {
      hour: '2-digit',
      minute: '2-digit'
    }).format(new Date(dateStr));
  };

  const checkLate = (est: string, act?: string) => {
    if (!act) return false;
    return new Date(act) > new Date(est);
  };

  // EKSPOR KE EXCEL (CSV)
  const exportToCSV = () => {
    if (logs.length === 0) return;

    const headers = [
      'Driver', 'Unit', 'Plat', 'Departemen', 'Tujuan', 'Keperluan', 
      'Berangkat', 'Estimasi Kembali', 'Aktual Kembali', 
      'Odo Awal', 'Odo Akhir', 'BBM Akhir', 'Kondisi'
    ];

    const csvRows = logs.map(log => [
      log.driverName,
      log.carName.split(' (')[0],
      log.carName.split('(')[1]?.replace(')', '') || '',
      log.department,
      log.destination,
      log.purpose.replace(/\n/g, ' '), // Clean newlines
      log.departureTime,
      log.estimatedArrivalTime,
      log.arrivalTime || '-',
      log.startOdometer,
      log.endOdometer || '-',
      log.endFuel || '-',
      log.endCondition || '-'
    ]);

    // Gunakan BOM (\ufeff) agar Excel membaca UTF-8 dengan benar
    const csvContent = "\ufeff" + [
      headers.join(','),
      ...csvRows.map(row => row.map(value => `"${value}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `LAPORAN_FLEET_${new Date().toISOString().split('T')[0]}.csv`);
    link.click();
  };

  // BACKUP DATABASE (JSON)
  const backupData = () => {
    const dataStr = JSON.stringify(logs, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `BACKUP_DATABASE_FLEET_${new Date().getTime()}.json`);
    link.click();
  };

  // RESTORE DATABASE (IMPORT)
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const importedLogs = JSON.parse(event.target?.result as string);
        if (Array.isArray(importedLogs)) {
          // Merge data lama dan baru (berdasarkan ID unik agar tidak double)
          const existingIds = new Set(logs.map(l => l.id));
          const newLogs = importedLogs.filter(l => !existingIds.has(l.id));

          if (newLogs.length === 0) {
            alert("Tidak ada data baru yang ditemukan dalam file.");
            return;
          }

          const combined = [...newLogs, ...logs];
          localStorage.setItem('fleet_logs', JSON.stringify(combined));
          alert(`${newLogs.length} Data baru berhasil digabungkan! Refresh halaman untuk melihat perubahan.`);
          window.location.reload();
        }
      } catch (err) {
        alert("Gagal membaca file. Pastikan formatnya benar (.json)");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="p-4 md:p-12 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-1 bg-fuchsia-600"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Archived Records</p>
          </div>
          <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tight">Log Aktivitas Operasional</h1>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          {/* Tombol Import (Hidden) */}
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImport} 
            accept=".json" 
            className="hidden" 
          />

          <button 
            onClick={() => fileInputRef.current?.click()}
            className="flex items-center justify-center gap-3 px-6 py-4 bg-slate-100 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 transition-all active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
            Sync Data
          </button>

          <button 
            onClick={exportToCSV}
            className="flex items-center justify-center gap-3 px-8 py-4 bg-green-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-green-700 transition-all shadow-xl shadow-green-100 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
            Excel Report
          </button>
        </div>
      </div>

      <div className="relative mb-8">
        <input
          type="text"
          placeholder="Cari Driver, Unit, atau Departemen..."
          value={searchTerm}
          onChange={e => setSearchTerm(e.target.value)}
          className="w-full pl-14 pr-8 py-5 bg-white border border-slate-100 rounded-[1.5rem] focus:border-fuchsia-500 outline-none transition-all font-black text-xs shadow-sm ring-1 ring-slate-50 placeholder:text-slate-300"
        />
        <div className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
