    navigator.clipboard.writeText(window.location.href);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="md:hidden flex items-center justify-between px-6 py-4 bg-slate-950 border-b border-slate-800 text-white sticky top-0 z-50">
      <div className="flex items-center gap-3">
