        <span className="font-black text-lg tracking-tight uppercase">PLA <span className="text-fuchsia-500">FLEET</span></span>
      </div>
      <button 
        onClick={handleShare}
        className="px-4 py-2 bg-fuchsia-600 rounded-xl text-[8px] font-black uppercase tracking-widest shadow-lg shadow-fuchsia-900/20"
      >
        {copied ? 'OK!' : 'Share'}
      </button>
    </div>
  );
}

