export default function App() {
  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('fleet_cars', JSON.stringify(cars));
  }, [cars]);

  useEffect(() => {
    localStorage.setItem('fleet_logs', JSON.stringify(logs));
  }, [logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs([newLog, ...logs]);
    setCars(prev => prev.map(c => 
      c.id === newLog.carId ? { ...c, status: 'on-duty' } : c
    ));
  };

  const extendLog = (logId: string, newTime: string, reason: string) => {
    setLogs(prev => prev.map(l => 
      l.id === logId 
        ? { 
            ...l, 
            estimatedArrivalTime: newTime,
            notes: l.notes ? `${l.notes} | Extended: ${reason}` : `Extended: ${reason}`
          } 
        : l
    ));
  };

  const completeLog = (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;

    setLogs(prev => prev.map(l => 
      l.id === logId 
        ? { 
            ...l, 
            status: 'completed' as const, 
            endOdometer: endData.endOdo, 
            endFuel: endData.endFuel,
            endCondition: endData.endCondition,
            arrivalTime: endData.arrivalTime 
          } 
        : l
    ));

    setCars(prev => prev.map(c => 
      c.id === logToFinish.carId ? { ...c, status: 'available' } : c
    ));
  };

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar />
        <MobileHeader />
        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} onExtend={extendLog} />} />
            <Route path="/dashboard" element={<DashboardPage cars={cars} logs={logs} onComplete={completeLog} />} />
            <Route path="/history" element={<HistoryPage logs={logs} />} />
          </Routes>
        </main>
        <BottomNav />
      </div>
    </HashRouter>
  );
}

import React, { useState, useRef } from 'react';
import { UsageLog } from '../types';

interface Props {
  logs: UsageLog[];
}

export default function HistoryPage({ logs }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filteredLogs = logs.filter(log => 
    log.driverName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.carName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    log.department.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const formatDate = (dateStr: string) => {
    return new Intl.DateTimeFormat('id-ID', {
      day: 'numeric',
      month: 'short',
      year: 'numeric'
    }).format(new Date(dateStr));
  };

  const formatTime = (dateStr: string) => {
    return new Intl.DateTimeFormat('id-ID', {
      hour: '2-digit',
      minute: '2-digit'
    }).format(new Date(dateStr));
  };

  const checkLate = (est: string, act?: string) => {
    if (!act) return false;
    return new Date(act) > new Date(est);
  };

  const exportToCSV = () => {
    if (logs.length === 0) return;

    const headers = [
      'Driver', 'Unit', 'Plat', 'Departemen', 'Tujuan', 'Keperluan', 
      'Berangkat', 'Estimasi Kembali', 'Aktual Kembali', 
      'Odo Awal', 'Odo Akhir', 'BBM Akhir', 'Kondisi Status'
    ];

    const csvRows = logs.map(log => [
      log.driverName,
      log.carName.split(' (')[0],
      log.carName.split('(')[1]?.replace(')', '') || '',
      log.department,
      log.destination,
      log.purpose.replace(/\n/g, ' '),
      log.departureTime,
      log.estimatedArrivalTime,
      log.arrivalTime || '-',
      log.startOdometer,
      log.endOdometer || '-',
      log.endFuel || '-',
      log.status === 'completed' ? 'Selesai' : 'Aktif'
    ]);

    const csvContent = "\ufeff" + [
      headers.join(','),
      ...csvRows.map(row => row.map(value => `"${value}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `REKAP_FLEET_PLA_${new Date().toISOString().split('T')[0]}.csv`);
    link.click();
  };

  const backupData = () => {
    const dataStr = JSON.stringify(logs, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `DATA_LOG_FLEET_PLA.json`);
    link.click();
    alert("Berhasil! Kirim file ini ke HRGA untuk rekapitulasi data.");
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const importedLogs = JSON.parse(event.target?.result as string);
        if (Array.isArray(importedLogs)) {
          const existingIds = new Set(logs.map(l => l.id));
          const newLogs = importedLogs.filter(l => !existingIds.has(l.id));

          if (newLogs.length === 0) {
            alert("Semua data di file ini sudah ada di sistem Anda.");
            return;
          }

          const combined = [...newLogs, ...logs];
          localStorage.setItem('fleet_logs', JSON.stringify(combined));
          alert(`${newLogs.length} Data baru berhasil digabungkan ke database pusat!`);
          window.location.reload();
        }
      } catch (err) {
        alert("Gagal membaca file data.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="p-4 md:p-12 max-w-7xl mx-auto animate-in fade-in duration-700">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-8 h-1 bg-fuchsia-600"></div>
            <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Centralized Data Hub</p>
          </div>
          <h1 className="text-3xl font-black text-slate-950 uppercase tracking-tight">Log Aktivitas Operasional</h1>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
           <button 
            onClick={exportToCSV}
            className="flex items-center justify-center gap-3 px-8 py-5 bg-green-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-green-700 transition-all shadow-xl shadow-green-100 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
            Rekap ke Excel
          </button>
        </div>
      </div>

      {/* Sync Instructions for Users */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
        <div className="bg-white border-2 border-slate-100 p-8 rounded-[2.5rem] shadow-sm">
          <p className="text-[10px] font-black text-fuchsia-600 uppercase tracking-widest mb-4 flex items-center gap-2">
            <span className="w-6 h-6 rounded-full bg-fuchsia-100 flex items-center justify-center text-[10px]">1</span> 
            Untuk Driver / User
          </p>
          <p className="text-xs font-bold text-slate-600 leading-relaxed mb-6">
            Selesai bertugas? Klik tombol di bawah untuk membuat file laporan, lalu kirimkan file tersebut ke HRGA melalui WhatsApp.
          </p>
          <button 
            onClick={backupData}
            className="w-full py-4 bg-slate-950 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-fuchsia-600 transition-all active:scale-95 flex items-center justify-center gap-3"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
            Download Laporan Saya
          </button>
        </div>

        <div className="bg-fuchsia-50/50 border-2 border-fuchsia-100 p-8 rounded-[2.5rem] shadow-sm">
          <p className="text-[10px] font-black text-fuchsia-600 uppercase tracking-widest mb-4 flex items-center gap-2">
            <span className="w-6 h-6 rounded-full bg-fuchsia-200 flex items-center justify-center text-[10px]">2</span> 
            Khusus Admin (HRGA)
          </p>
          <p className="text-xs font-bold text-slate-600 leading-relaxed mb-6">
            Terima file laporan dari Driver? Klik tombol di bawah untuk menggabungkan data mereka ke database pusat Anda.
          </p>
          <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-full py-4 bg-white border-2 border-fuchsia-200 text-fuchsia-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-fuchsia-100 transition-all active:scale-95 flex items-center justify-center gap-3 shadow-lg shadow-fuchsia-100"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
            Import Data Driver
          </button>
        </div>
      </div>

      {/* Table Section */}
      <div className="relative mb-8">
        <input
          type="text"
          placeholder="Cari Driver, Unit, atau Departemen..."
          value={searchTerm}
          onChange={e => setSearchTerm(e.target.value)}
          className="w-full pl-14 pr-8 py-5 bg-white border border-slate-100 rounded-[1.5rem] focus:border-fuchsia-500 outline-none transition-all font-black text-xs shadow-sm ring-1 ring-slate-50 placeholder:text-slate-300"
        />
        <div className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300">
