        </div>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-2xl shadow-slate-200/50 overflow-hidden ring-1 ring-slate-50">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead>
              <tr className="bg-slate-950 text-white">
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900">User & Armada</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900">Tujuan</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900 text-center">Waktu Berangkat</th>
                <th className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.2em] border-r border-slate-900 text-center">Estimasi vs Aktual</th>
