export default function App() {
  const [syncStatus, setSyncStatus] = useState<'online' | 'offline' | 'loading'>('offline');
  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  // Fungsi untuk mengambil data terbaru dari Cloud
  const fetchLatestData = useCallback(async () => {
    if (!CLOUD_CONFIG.active) return;
    setSyncStatus('loading');

    // Logika simulasi fetch cloud
    // Jika nanti sudah pakai Supabase, kodenya diletakkan di sini
    setTimeout(() => {
      setSyncStatus('online');
      console.log("Data cloud disinkronkan...");
    }, 1000);
  }, []);

  useEffect(() => {
    fetchLatestData();
    // Auto-refresh data setiap 30 detik agar selalu update
    const interval = setInterval(fetchLatestData, 30000);
    return () => clearInterval(interval);
  }, [fetchLatestData]);

  useEffect(() => {
    localStorage.setItem('fleet_cars', JSON.stringify(cars));
    localStorage.setItem('fleet_logs', JSON.stringify(logs));
  }, [cars, logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs([newLog, ...logs]);
    setCars(prev => prev.map(c => c.id === newLog.carId ? { ...c, status: 'on-duty' } : c));
    // Jika Cloud aktif, langsung kirim data ke sana (POST)
  };

  const completeLog = (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;

    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'completed' as const, ...endData } : l));
    setCars(prev => prev.map(c => c.id === logToFinish.carId ? { ...c, status: 'available' } : c));
    // Update status ke Cloud juga
  };

  const extendLog = (logId: string, newTime: string, reason: string) => {
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, estimatedArrivalTime: newTime, notes: l.notes ? `${l.notes} | Ext: ${reason}` : `Ext: ${reason}` } : l));
  };

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar syncStatus={syncStatus} />
        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} onExtend={extendLog} />} />
            <Route path="/dashboard" element={<DashboardPage cars={cars} logs={logs} onComplete={completeLog} />} />
            <Route path="/history" element={<HistoryPage logs={logs} />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
}

