    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotoPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedLogId || !endData.endOdo) return;

    onComplete(selectedLogId, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition,
      arrivalTime: new Date(endData.arrivalTime).toISOString(),
      returnPhoto: photoPreview || undefined
    });

    setSubmitted('returned');
    setSelectedLogId(null);
    setPhotoPreview(null);
    setEndData({
      endOdo: '',
      endFuel: '1/2',
      endCondition: 'BAIK',
      arrivalTime: new Date().toISOString().slice(0, 16)
    });

    setTimeout(() => setSubmitted(null), 3000);
  };

  const fuelOptions: FuelLevel[] = ['E', '1/4', '1/2', '3/4', 'F'];

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-12 animate-in fade-in duration-700">
      <div className="mb-12">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-1 bg-fuchsia-600"></div>
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Fleet Operations</p>
        </div>
        <h1 className="text-3xl md:text-4xl font-black text-slate-950 uppercase tracking-tight leading-tight">Kelola Penggunaan Unit</h1>
        <p className="text-slate-500 font-bold text-xs uppercase tracking-widest mt-2">Pilih unit Anda untuk konfirmasi balik atau perpanjang waktu</p>
      </div>

      {submitted === 'returned' && (
