import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Car, UsageLog, FuelLevel, VehicleCondition } from './types';
import { INITIAL_CARS, Icons } from './constants';
import FormPage from './pages/FormPage';
import DashboardPage from './pages/DashboardPage';
import HistoryPage from './pages/HistoryPage';
import ReturnPage from './pages/ReturnPage';

export default function App() {
  const [syncStatus, setSyncStatus] = useState<'online' | 'offline' | 'loading'>('offline');
  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('fleet_cars', JSON.stringify(cars));
    localStorage.setItem('fleet_logs', JSON.stringify(logs));
  }, [cars, logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs([newLog, ...logs]);
    setCars(prev => prev.map(c => c.id === newLog.carId ? { ...c, status: 'requested' } : c));
  };

  const approveLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'active' as const } : l));
    setCars(prev => prev.map(c => c.id === log.carId ? { ...c, status: 'on-duty' } : c));
  };

  const rejectLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'rejected' as const } : l));
    setCars(prev => prev.map(c => c.id === log.carId ? { ...c, status: 'available' } : c));
  };

  const completeLog = (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string, returnPhoto?: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;

    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'completed' as const, ...endData } : l));
    setCars(prev => prev.map(c => c.id === logToFinish.carId ? { ...c, status: 'available' } : c));
  };

  const toggleMaintenance = (carId: string) => {
    setCars(prev => prev.map(c => {
      if (c.id === carId) {
        return { ...c, status: c.status === 'maintenance' ? 'available' : 'maintenance' };
      }
      return c;
    }));
  };

  const pendingCount = logs.filter(l => l.status === 'pending').length;

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar syncStatus={syncStatus} pendingCount={pendingCount} />
        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} onExtend={() => {}} />} />
            <Route path="/dashboard" element={<DashboardPage cars={cars} logs={logs} onComplete={completeLog} onApprove={approveLog} onReject={rejectLog} onToggleMaintenance={toggleMaintenance} />} />
            <Route path="/history" element={<HistoryPage logs={logs} />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
}

function Sidebar({ syncStatus, pendingCount }: { syncStatus: string, pendingCount: number }) {
  const location = useLocation();
  const [copied, setCopied] = useState(false);

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="hidden md:flex flex-col w-72 bg-slate-950 border-r border-slate-800 min-h-screen sticky top-0 text-white shadow-2xl">
      <div className="p-8 border-b border-slate-900 flex items-center gap-4">
        <div className="w-10 h-10 bg-fuchsia-600 rounded-xl flex items-center justify-center shadow-lg shadow-fuchsia-900/20">
           <Icons.Car />
        </div>
        <div>
          <span className="font-black text-white text-xl tracking-tight block leading-none uppercase">PLA <span className="text-fuchsia-500">FLEET</span></span>
          <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em]">HRGA Division</span>
        </div>
      </div>

      <nav className="flex-1 p-6 space-y-2 mt-4">
        {[
          { path: '/', label: 'Ambil Mobil', icon: <Icons.Clipboard /> },
          { path: '/return', label: 'Balik Mobil', icon: <Icons.Return /> },
          { path: '/dashboard', label: 'Monitoring', icon: <Icons.Layout />, badge: pendingCount },
          { path: '/history', label: 'Database', icon: <Icons.History /> },
        ].map((item) => (
          <Link
            key={item.path}
            to={item.path}
            className={`flex items-center justify-between px-6 py-4 rounded-2xl transition-all font-black text-[11px] uppercase tracking-widest ${
              location.pathname === item.path ? 'bg-fuchsia-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'
            }`}
          >
            <span className="flex items-center gap-4">{item.icon} {item.label}</span>
            {item.badge && item.badge > 0 && (
              <span className="bg-amber-500 text-slate-950 px-2 py-0.5 rounded-lg text-[10px] animate-pulse">
                {item.badge}
              </span>
            )}
          </Link>
        ))}
      </nav>

      <div className="p-6 border-t border-slate-900 space-y-4">
        <div className={`flex items-center gap-3 px-5 py-3 rounded-xl border ${
          syncStatus === 'online' ? 'bg-green-500/10 border-green-500/20 text-green-500' : 
          'bg-amber-500/10 border-amber-500/20 text-amber-500'
        }`}>
          <div className={`w-2 h-2 rounded-full ${syncStatus === 'online' ? 'bg-green-500' : 'bg-amber-500 animate-pulse'}`}></div>
          <span className="text-[9px] font-black uppercase tracking-widest">
            {syncStatus === 'online' ? 'Cloud Connected' : 'Wait for Setup'}
          </span>
        </div>

        <button onClick={handleShare} className="w-full py-4 bg-slate-900 border border-slate-800 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all flex items-center justify-center gap-2 text-center">
          Share App
        </button>
      </div>
    </div>
  );
}

