import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { Car, UsageLog, FuelLevel, VehicleCondition } from './types';
import { INITIAL_CARS, Icons } from './constants';
import FormPage from './pages/FormPage';
import DashboardPage from './pages/DashboardPage';
import HistoryPage from './pages/HistoryPage';
import ReturnPage from './pages/ReturnPage';

export default function App() {
  const [syncStatus, setSyncStatus] = useState<'online' | 'offline' | 'loading'>('offline');
  const [isAdmin, setIsAdmin] = useState(() => {
    return sessionStorage.getItem('admin_auth') === 'true';
  });

  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('fleet_cars', JSON.stringify(cars));
    localStorage.setItem('fleet_logs', JSON.stringify(logs));
  }, [cars, logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs([newLog, ...logs]);
    setCars(prev => prev.map(c => c.id === newLog.carId ? { ...c, status: 'requested' } : c));
  };

  const approveLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'active' as const } : l));
    setCars(prev => prev.map(c => c.id === log.carId ? { ...c, status: 'on-duty' } : c));
  };

  const rejectLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'rejected' as const } : l));
    setCars(prev => prev.map(c => c.id === log.carId ? { ...c, status: 'available' } : c));
  };

  const completeLog = (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string, returnPhoto?: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;

    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'completed' as const, ...endData } : l));
    setCars(prev => prev.map(c => c.id === logToFinish.carId ? { ...c, status: 'available' } : c));
  };

  const toggleMaintenance = (carId: string) => {
    setCars(prev => prev.map(c => {
      if (c.id === carId) {
        return { ...c, status: c.status === 'maintenance' ? 'available' : 'maintenance' };
      }
      return c;
    }));
  };

  const handleAdminAuth = (pin: string) => {
    if (pin === '1234') { // Kode Admin Default
      setIsAdmin(true);
      sessionStorage.setItem('admin_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAdmin(false);
    sessionStorage.removeItem('admin_auth');
  };

  const pendingCount = logs.filter(l => l.status === 'pending').length;

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar syncStatus={syncStatus} pendingCount={pendingCount} isAdmin={isAdmin} onLogout={handleLogout} />
        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} onExtend={() => {}} />} />
            <Route 
              path="/dashboard" 
              element={isAdmin ? <DashboardPage cars={cars} logs={logs} onComplete={completeLog} onApprove={approveLog} onReject={rejectLog} onToggleMaintenance={toggleMaintenance} /> : <AdminGuard onAuth={handleAdminAuth} />} 
            />
            <Route 
              path="/history" 
              element={isAdmin ? <HistoryPage logs={logs} /> : <AdminGuard onAuth={handleAdminAuth} />} 
            />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
}

function AdminGuard({ onAuth }: { onAuth: (pin: string) => boolean }) {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (onAuth(pin)) {
      setError(false);
    } else {
      setError(true);
      setPin('');
    }
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center p-6 animate-in fade-in zoom-in duration-500">
      <div className="bg-white rounded-[3rem] p-12 shadow-2xl border border-slate-100 max-w-sm w-full text-center">
        <div className="w-20 h-20 bg-fuchsia-100 text-fuchsia-600 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner">
