        <div className={`flex items-center gap-3 px-5 py-3 rounded-xl border border-amber-500/20 bg-amber-500/10 text-amber-500`}>
          <div className={`w-2 h-2 rounded-full bg-amber-500 animate-pulse`}></div>
          <span className="text-[9px] font-black uppercase tracking-widest">
            Local Storage Mode
          </span>
        </div>

        <button onClick={handleShare} className="w-full py-4 bg-slate-900 border border-slate-800 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all flex items-center justify-center gap-2 text-center">
