    const saved = localStorage.getItem('pla_fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  // Simulasi Sinkronisasi Real-time
  // Dalam skenario nyata, ini akan memanggil API (misal: Firebase/Sheets)
  const syncWithCloud = useCallback(() => {
    setIsSyncing(true);

    // Simulasi Delay Network
    setTimeout(() => {
      const cloudLogs = localStorage.getItem('pla_fleet_logs');
      if (cloudLogs) {
        const parsedLogs = JSON.parse(cloudLogs);
        // Merge logic: Ambil data terbaru yang belum ada di local state
        setLogs(current => {
          const existingIds = new Set(current.map(l => l.id));
          const freshLogs = parsedLogs.filter((l: UsageLog) => !existingIds.has(l.id));
          if (freshLogs.length > 0) return [...freshLogs, ...current];
          return current;
        });
      }

      const cloudCars = localStorage.getItem('pla_fleet_cars');
      if (cloudCars) {
        setCars(JSON.parse(cloudCars));
      }

      setIsSyncing(false);
      setLastSync(new Date().toLocaleTimeString());
    }, 800);
  }, []);

  // Auto-sync setiap 5 detik (seperti Google Form yang auto-save)
  useEffect(() => {
    const interval = setInterval(syncWithCloud, 5000);
    window.addEventListener('storage', syncWithCloud); // Sync jika ada tab lain yang update
    return () => {
      clearInterval(interval);
      window.removeEventListener('storage', syncWithCloud);
    };
  }, [syncWithCloud]);

  // Save to "Cloud" (LocalStorage sebagai proxy cloud)
  useEffect(() => {
    localStorage.setItem('pla_fleet_cars', JSON.stringify(cars));
    localStorage.setItem('pla_fleet_logs', JSON.stringify(logs));
  }, [cars, logs]);

  const addLog = (newLog: UsageLog) => {
    setLogs(prev => [newLog, ...prev]);
    setCars(prev => prev.map(c => c.id === newLog.carId ? { ...c, status: 'requested' } : c));
  };

  const approveLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'active' as const } : l));
    setCars(prev => prev.map(c => c.id === log.carId ? { ...c, status: 'on-duty' } : c));
  };

  const rejectLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'rejected' as const } : l));
    setCars(prev => prev.map(c => c.id === log.carId ? { ...c, status: 'available' } : c));
  };

  const completeLog = (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string, returnPhoto?: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;
    setLogs(prev => prev.map(l => l.id === logId ? { ...l, status: 'completed' as const, ...endData } : l));
    setCars(prev => prev.map(c => c.id === logToFinish.carId ? { ...c, status: 'available' } : c));
  };

  const toggleMaintenance = (carId: string) => {
    setCars(prev => prev.map(c => c.id === carId ? { ...c, status: c.status === 'maintenance' ? 'available' : 'maintenance' } : c));
  };

  const handleAdminAuth = (pin: string) => {
    if (pin === '1234') { 
      setIsAdmin(true);
      sessionStorage.setItem('admin_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAdmin(false);
    sessionStorage.removeItem('admin_auth');
  };

  return (
