import { GoogleGenAI } from "@google/genai";
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Car, UsageLog, FuelLevel, VehicleCondition } from './types';
import { INITIAL_CARS, Icons } from './constants';
import FormPage from './pages/FormPage';
import DashboardPage from './pages/DashboardPage';
import HistoryPage from './pages/HistoryPage';
import ReturnPage from './pages/ReturnPage';

// Kita gunakan npoint.io sebagai public JSON storage sederhana untuk demo sinkronisasi real-time
const CLOUD_API_BASE = "https://api.npoint.io/e089285093556d11e54a"; // Ini adalah ID Demo, idealnya buat ID unik per user

export default function App() {
  const [isAdmin, setIsAdmin] = useState(() => sessionStorage.getItem('admin_auth') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<string>("-");
  const [networkError, setNetworkError] = useState(false);

  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('pla_fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('pla_fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  // FUNGSI UTAMA: Ambil data dari Cloud (Download)
  const fetchFromCloud = useCallback(async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    try {
      const response = await fetch(CLOUD_API_BASE);
      if (response.ok) {
        const cloudData = await response.json();

        // Merge Logs: Hanya tambah yang belum ada di lokal
        if (cloudData.logs) {
          setLogs(current => {
            const existingIds = new Set(current.map(l => l.id));
            const newOnes = cloudData.logs.filter((l: UsageLog) => !existingIds.has(l.id));
            if (newOnes.length > 0) {
              const merged = [...newOnes, ...current].sort((a, b) => 
                new Date(b.requestDate).getTime() - new Date(a.requestDate).getTime()
              );
              return merged;
            }
            return current;
          });
        }

        // Sync Cars Status
        if (cloudData.cars) {
          setCars(cloudData.cars);
        }

        setNetworkError(false);
        setLastSync(new Date().toLocaleTimeString());
      }
    } catch (error) {
      console.error("Sync Error:", error);
      setNetworkError(true);
    } finally {
      setIsSyncing(false);
    }
  }, [isSyncing]);

  // FUNGSI UTAMA: Simpan data ke Cloud (Upload)
  const pushToCloud = useCallback(async (currentCars: Car[], currentLogs: UsageLog[]) => {
    try {
      await fetch(CLOUD_API_BASE, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cars: currentCars, logs: currentLogs })
      });
    } catch (error) {
      console.error("Push to Cloud failed:", error);
    }
  }, []);

  // Polling: Cek data baru setiap 7 detik
  useEffect(() => {
    fetchFromCloud(); // Initial fetch
    const interval = setInterval(fetchFromCloud, 7000);
    return () => clearInterval(interval);
  }, []);

  // Simpan ke LocalStorage sebagai backup & trigger push ke cloud saat ada perubahan
  useEffect(() => {
    localStorage.setItem('pla_fleet_cars', JSON.stringify(cars));
    localStorage.setItem('pla_fleet_logs', JSON.stringify(logs));
    // Kita panggil push hanya jika ada perubahan yang bukan dari hasil fetch
  }, [cars, logs]);

  const addLog = async (newLog: UsageLog) => {
    const updatedLogs = [newLog, ...logs];
    const updatedCars = cars.map(c => c.id === newLog.carId ? { ...c, status: 'requested' as const } : c);
    setLogs(updatedLogs);
    setCars(updatedCars);
    await pushToCloud(updatedCars, updatedLogs);
  };

  const approveLog = async (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    const updatedLogs = logs.map(l => l.id === logId ? { ...l, status: 'active' as const } : l);
    const updatedCars = cars.map(c => c.id === log.carId ? { ...c, status: 'on-duty' as const } : c);
    setLogs(updatedLogs);
    setCars(updatedCars);
    await pushToCloud(updatedCars, updatedLogs);
  };

  const rejectLog = async (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    const updatedLogs = logs.map(l => l.id === logId ? { ...l, status: 'rejected' as const } : l);
    const updatedCars = cars.map(c => c.id === log.carId ? { ...c, status: 'available' as const } : c);
    setLogs(updatedLogs);
    setCars(updatedCars);
    await pushToCloud(updatedCars, updatedLogs);
  };

  const completeLog = async (logId: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string, returnPhoto?: string }) => {
    const logToFinish = logs.find(l => l.id === logId);
    if (!logToFinish) return;
    const updatedLogs = logs.map(l => l.id === logId ? { ...l, status: 'completed' as const, ...endData } : l);
    const updatedCars = cars.map(c => c.id === logToFinish.carId ? { ...c, status: 'available' as const } : c);
    setLogs(updatedLogs);
    setCars(updatedCars);
    await pushToCloud(updatedCars, updatedLogs);
  };

  const toggleMaintenance = async (carId: string) => {
    const updatedCars = cars.map(c => c.id === carId ? { ...c, status: c.status === 'maintenance' ? 'available' : 'maintenance' } : c);
    setCars(updatedCars);
    await pushToCloud(updatedCars, logs);
  };

  const handleAdminAuth = (pin: string) => {
    if (pin === '1234') { 
      setIsAdmin(true);
      sessionStorage.setItem('admin_auth', 'true');
      return true;
    }
    return false;
  };

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar isAdmin={isAdmin} isSyncing={isSyncing} lastSync={lastSync} networkError={networkError} onLogout={() => setIsAdmin(false)} pendingCount={logs.filter(l => l.status === 'pending').length} />

        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden relative">
          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} onExtend={() => {}} />} />
            <Route 
              path="/dashboard" 
              element={isAdmin ? <DashboardPage cars={cars} logs={logs} onComplete={completeLog} onApprove={approveLog} onReject={rejectLog} onToggleMaintenance={toggleMaintenance} /> : <AdminGuard onAuth={handleAdminAuth} />} 
            />
            <Route 
              path="/history" 
              element={isAdmin ? <HistoryPage logs={logs} onImportLogs={() => {}} /> : <AdminGuard onAuth={handleAdminAuth} />} 
            />
          </Routes>
        </main>

        <div className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-950 text-white p-4 flex justify-around items-center border-t border-slate-800 z-50">
           <Link to="/" className="p-3"><Icons.Clipboard /></Link>
           <Link to="/return" className="p-3"><Icons.Return /></Link>
           <Link to="/dashboard" className="p-3 relative"><Icons.Layout />{logs.filter(l => l.status === 'pending').length > 0 && <div className="absolute top-2 right-2 w-2 h-2 bg-amber-500 rounded-full"></div>}</Link>
        </div>
      </div>
    </HashRouter>
  );
}

