import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Car, UsageLog, FuelLevel, VehicleCondition } from './types';
import { INITIAL_CARS, Icons } from './constants';
import FormPage from './pages/FormPage';
import DashboardPage from './pages/DashboardPage';
import HistoryPage from './pages/HistoryPage';
import ReturnPage from './pages/ReturnPage';

// Kita gunakan npoint sebagai storage bin. 
// Untuk sistem yang lebih masif, disarankan menggunakan Firebase/Supabase.
const DEFAULT_BIN = "e089285093556d11e54a";

export default function App() {
  const [isAdmin, setIsAdmin] = useState(() => sessionStorage.getItem('admin_auth') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<string>("-");
  const [networkError, setNetworkError] = useState(false);

  // Ambil atau buat ID Network unik agar data tidak tercampur antar perusahaan
  const [networkId] = useState(() => {
    const params = new URLSearchParams(window.location.search);
    const existing = params.get('net') || localStorage.getItem('pla_network_id');
    if (existing) return existing;
    const nuevo = `FLEET-${Math.random().toString(36).substring(2, 8).toUpperCase()}`;
    localStorage.setItem('pla_network_id', nuevo);
    return nuevo;
  });

  const [cars, setCars] = useState<Car[]>(() => {
    const saved = localStorage.getItem('pla_fleet_cars');
    return saved ? JSON.parse(saved) : INITIAL_CARS;
  });

  const [logs, setLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('pla_fleet_logs');
    return saved ? JSON.parse(saved) : [];
  });

  const CLOUD_URL = `https://api.npoint.io/${DEFAULT_BIN}`;

  // SYNC ENGINE: Download dari Cloud
  const syncFromCloud = useCallback(async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    try {
      const response = await fetch(CLOUD_URL);
      if (response.ok) {
        const cloudData = await response.json();
        const networkData = cloudData[networkId] || { cars: INITIAL_CARS, logs: [] };

        // Merge Logs Logic (Gunakan ID unik agar tidak duplikat)
        setLogs(current => {
          const currentIds = new Set(current.map(l => l.id));
          const newLogsFromCloud = networkData.logs.filter((l: UsageLog) => !currentIds.has(l.id));

          if (newLogsFromCloud.length > 0) {
            const merged = [...newLogsFromCloud, ...current].sort((a, b) => 
              new Date(b.requestDate).getTime() - new Date(a.requestDate).getTime()
            );
            return merged;
          }

          // Update status logs yang sudah ada (misal dari pending ke active)
          return current.map(localLog => {
            const cloudVersion = networkData.logs.find((l: UsageLog) => l.id === localLog.id);
            return cloudVersion || localLog;
          });
        });

        setCars(networkData.cars || INITIAL_CARS);
        setNetworkError(false);
        setLastSync(new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
      }
    } catch (e) {
      setNetworkError(true);
    } finally {
      setIsSyncing(false);
    }
  }, [networkId, isSyncing]);

  // SYNC ENGINE: Upload ke Cloud
  const pushToCloud = useCallback(async (newCars: Car[], newLogs: UsageLog[]) => {
    try {
      // Ambil data semua network dulu agar tidak menghapus data network lain di bin yang sama
      const getRes = await fetch(CLOUD_URL);
      const allCloudData = getRes.ok ? await getRes.json() : {};

      allCloudData[networkId] = { cars: newCars, logs: newLogs };

      await fetch(CLOUD_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(allCloudData)
      });
      setLastSync(new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
    } catch (e) {
      console.error("Upload failed", e);
    }
  }, [networkId]);

  // Auto-Sync Polling
  useEffect(() => {
    syncFromCloud();
    const timer = setInterval(syncFromCloud, 8000); // Cek data tiap 8 detik
    return () => clearInterval(timer);
  }, []);

  // Update Local Storage & Cloud saat ada aksi
  const updateData = async (updatedCars: Car[], updatedLogs: UsageLog[]) => {
    setCars(updatedCars);
    setLogs(updatedLogs);
    localStorage.setItem('pla_fleet_cars', JSON.stringify(updatedCars));
    localStorage.setItem('pla_fleet_logs', JSON.stringify(updatedLogs));
    await pushToCloud(updatedCars, updatedLogs);
  };

  const addLog = (newLog: UsageLog) => {
    const updatedLogs = [newLog, ...logs];
    const updatedCars = cars.map(c => c.id === newLog.carId ? { ...c, status: 'requested' as const } : c);
    updateData(updatedCars, updatedLogs);
  };

  const approveLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    const updatedLogs = logs.map(l => l.id === logId ? { ...l, status: 'active' as const } : l);
    const updatedCars = cars.map(c => c.id === log.carId ? { ...c, status: 'on-duty' as const } : c);
    updateData(updatedCars, updatedLogs);
  };

  const rejectLog = (logId: string) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    const updatedLogs = logs.map(l => l.id === logId ? { ...l, status: 'rejected' as const } : l);
    const updatedCars = cars.map(c => c.id === log.carId ? { ...c, status: 'available' as const } : c);
    updateData(updatedCars, updatedLogs);
  };

  const completeLog = (logId: string, endData: any) => {
    const log = logs.find(l => l.id === logId);
    if (!log) return;
    const updatedLogs = logs.map(l => l.id === logId ? { ...l, status: 'completed' as const, ...endData } : l);
    const updatedCars = cars.map(c => c.id === log.carId ? { ...c, status: 'available' as const } : c);
    updateData(updatedCars, updatedLogs);
  };

  const toggleMaintenance = (carId: string) => {
    const updatedCars: Car[] = cars.map(c => c.id === carId ? { ...c, status: (c.status === 'maintenance' ? 'available' : 'maintenance') as any } : c);
    updateData(updatedCars, logs);
  };

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen w-full bg-[#f8fafc] text-slate-900">
        <Sidebar 
          isAdmin={isAdmin} 
          isSyncing={isSyncing} 
          lastSync={lastSync} 
          networkError={networkError} 
          networkId={networkId}
          onLogout={() => { setIsAdmin(false); sessionStorage.removeItem('admin_auth'); }} 
          pendingCount={logs.filter(l => l.status === 'pending').length} 
        />

        <main className="flex-1 w-full pb-24 md:pb-0 overflow-x-hidden relative">
          {/* Mobile Cloud Status Bar */}
          <div className="md:hidden sticky top-0 z-[60] bg-white/80 backdrop-blur-md border-b border-slate-100 p-3 flex justify-between items-center px-6">
             <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-fuchsia-500 animate-ping' : 'bg-green-500'}`}></div>
                <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">{isSyncing ? 'Syncing...' : 'Live'}</span>
             </div>
             <span className="text-[9px] font-black uppercase text-fuchsia-600">{networkId}</span>
          </div>

          <Routes>
            <Route path="/" element={<FormPage cars={cars} onSubmit={addLog} />} />
            <Route path="/return" element={<ReturnPage logs={logs} onComplete={completeLog} onExtend={() => {}} />} />
            <Route 
              path="/dashboard" 
              element={isAdmin ? <DashboardPage cars={cars} logs={logs} onComplete={completeLog} onApprove={approveLog} onReject={rejectLog} onToggleMaintenance={toggleMaintenance} /> : <AdminGuard onAuth={(pin) => { if(pin === '1234') { setIsAdmin(true); sessionStorage.setItem('admin_auth', 'true'); return true; } return false; }} />} 
            />
            <Route 
              path="/history" 
              element={isAdmin ? <HistoryPage logs={logs} onImportLogs={() => {}} /> : <AdminGuard onAuth={() => false} />} 
            />
          </Routes>
        </main>

        <div className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-950 text-white p-4 flex justify-around items-center border-t border-slate-800 z-50">
           <Link to="/" className="p-3"><Icons.Clipboard /></Link>
           <Link to="/return" className="p-3"><Icons.Return /></Link>
           <Link to="/dashboard" className="p-3 relative">
             <Icons.Layout />
             {logs.filter(l => l.status === 'pending').length > 0 && <div className="absolute top-2 right-2 w-2.5 h-2.5 bg-amber-500 rounded-full border-2 border-slate-950"></div>}
           </Link>
        </div>
      </div>
    </HashRouter>
  );
}

function Sidebar({ isAdmin, isSyncing, lastSync, networkError, networkId, onLogout, pendingCount }: any) {
  const location = useLocation();
  const [copied, setCopied] = useState(false);

  const shareLink = () => {
