          <div className="flex items-center justify-between mb-2">
            <span className="text-[8px] font-black uppercase text-slate-400">ID Kantor: {networkId}</span>
            <div className={`w-2 h-2 rounded-full ${networkError ? 'bg-red-500' : (isSyncing ? 'bg-fuchsia-500 animate-ping' : 'bg-green-500')}`}></div>
