    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="hidden md:flex flex-col w-80 bg-slate-950 border-r border-slate-800 min-h-screen sticky top-0 text-white shadow-2xl z-50">
      <div className="p-10 border-b border-slate-900 flex items-center gap-5">
        <div className="w-12 h-12 bg-fuchsia-600 rounded-2xl flex items-center justify-center shadow-lg shadow-fuchsia-500/20"><Icons.Car /></div>
        <div>
          <span className="font-black text-white text-xl tracking-tight block uppercase">PLA <span className="text-fuchsia-500">FLEET</span></span>
          <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest block mt-1">HRGA MONITORING</span>
        </div>
      </div>

      <nav className="flex-1 p-6 space-y-2 mt-4">
        {[
          { path: '/', label: 'Ambil Mobil', icon: <Icons.Clipboard /> },
          { path: '/return', label: 'Balik Mobil', icon: <Icons.Return /> },
          { path: '/dashboard', label: 'Monitoring', icon: <Icons.Layout />, badge: pendingCount },
          { path: '/history', label: 'Database', icon: <Icons.History /> },
        ].map((item) => (
          <Link key={item.path} to={item.path} className={`flex items-center justify-between px-6 py-4 rounded-2xl transition-all font-black text-[10px] uppercase tracking-widest ${location.pathname === item.path ? 'bg-fuchsia-600 text-white shadow-xl translate-x-2' : 'text-slate-500 hover:text-white hover:bg-white/5'}`}>
            <span className="flex items-center gap-4">{item.icon} {item.label}</span>
            {item.badge && item.badge > 0 && <span className="bg-amber-500 text-slate-950 px-2.5 py-1 rounded-lg text-[9px] animate-pulse">{item.badge}</span>}
          </Link>
        ))}
      </nav>

      <div className="p-8 border-t border-slate-900 space-y-4">
        <div className={`px-5 py-4 rounded-2xl border transition-all ${networkError ? 'border-red-500 bg-red-500/10' : 'border-slate-800 bg-slate-900/50'}`}>
          <div className="flex items-center justify-between mb-1">
            <span className="text-[7px] font-black uppercase text-slate-500">KANTOR ID: {networkId}</span>
            <div className={`w-1.5 h-1.5 rounded-full ${isSyncing ? 'bg-fuchsia-500 animate-ping' : 'bg-green-500'}`}></div>
          </div>
          <p className="text-[9px] font-black uppercase tracking-widest">{networkError ? 'Sync Offline' : 'Cloud Active'}</p>
          <p className="text-[7px] font-bold text-slate-600 mt-1 uppercase">SINKRON: {lastSync}</p>
        </div>

        <button onClick={shareLink} className={`w-full py-5 rounded-2xl text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all active:scale-95 ${copied ? 'bg-green-600 text-white' : 'bg-white text-slate-950 hover:bg-fuchsia-600 hover:text-white shadow-xl'}`}>
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8"/><polyline points="16 6 12 2 8 6"/><line x1="12" x2="12" y1="2" y2="15"/></svg>
          {copied ? 'LINK TERSALIN!' : 'SALIN LINK DRIVER'}
        </button>

        {isAdmin && <button onClick={onLogout} className="w-full py-4 text-red-500 border border-red-500/10 rounded-2xl text-[8px] font-black uppercase tracking-widest hover:bg-red-600 hover:text-white transition-all">Logout Admin</button>}
      </div>
    </div>
  );
}

function AdminGuard({ onAuth }: any) {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);
  return (
    <div className="min-h-[80vh] flex items-center justify-center p-6">
      <div className="bg-white rounded-[3rem] p-12 shadow-2xl border border-slate-100 max-w-sm w-full text-center">
        <h2 className="text-xl font-black text-slate-950 uppercase mb-8 tracking-tighter">Admin Control</h2>
        <form onSubmit={(e) => { e.preventDefault(); if(!onAuth(pin)) { setError(true); setPin(''); } }} className="space-y-6">
          <input type="password" value={pin} onChange={e => setPin(e.target.value)} maxLength={4} className={`w-full py-6 bg-slate-50 border-4 rounded-3xl text-center text-4xl font-black outline-none ${error ? 'border-red-500 animate-shake' : 'border-slate-50 focus:border-fuchsia-500'}`} placeholder="****" autoFocus />
          <button type="submit" className="w-full py-5 bg-slate-950 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-fuchsia-600 transition-all">Unlock Access</button>
        </form>
      </div>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { UsageLog, FuelLevel, VehicleCondition } from '../types';
import { Icons } from '../constants';

interface Props {
  logs: UsageLog[];
  onComplete: (id: string, endData: { endOdo: number, endFuel: FuelLevel, endCondition: VehicleCondition, arrivalTime: string, returnPhoto?: string }) => void;
  onExtend: (id: string, newTime: string, reason: string) => void;
}

export default function ReturnPage({ logs, onComplete, onExtend }: Props) {
  const activeLogs = logs.filter(l => l.status === 'active');
  const [selectedLogId, setSelectedLogId] = useState<string | null>(null);
  const [submitted, setSubmitted] = useState<'returned' | 'extended' | null>(null);
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);
  const [odoError, setOdoError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [endData, setEndData] = useState({
    endOdo: '',
    endFuel: '1/2' as FuelLevel,
    endCondition: 'BAIK' as VehicleCondition,
    arrivalTime: new Date().toISOString().slice(0, 16)
  });

  const selectedLog = logs.find(l => l.id === selectedLogId);
  const isEV = selectedLog?.carName.toUpperCase().includes('BYD');

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setPhotoPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleOdoChange = (val: string) => {
    setEndData({ ...endData, endOdo: val });
    if (selectedLog && val) {
      const numVal = parseInt(val);
      if (numVal < selectedLog.startOdometer) {
        setOdoError(`KM Akhir (${numVal}) tidak boleh lebih kecil dari KM Awal (${selectedLog.startOdometer})`);
      } else {
        setOdoError(null);
      }
    } else {
      setOdoError(null);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedLogId || !endData.endOdo || odoError) return;

    onComplete(selectedLogId, {
      endOdo: parseInt(endData.endOdo),
      endFuel: endData.endFuel,
      endCondition: endData.endCondition,
      arrivalTime: new Date(endData.arrivalTime).toISOString(),
      returnPhoto: photoPreview || undefined
    });

    setSubmitted('returned');
    setSelectedLogId(null);
    setPhotoPreview(null);
    setEndData({
      endOdo: '',
      endFuel: '1/2',
      endCondition: 'BAIK',
      arrivalTime: new Date().toISOString().slice(0, 16)
    });

    setTimeout(() => setSubmitted(null), 5000);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const fuelOptions: { value: FuelLevel; label: string; batteryLabel: string }[] = [
    { value: 'E', label: 'E', batteryLabel: '<20%' },
    { value: '1/4', label: '1/4', batteryLabel: '40%' },
    { value: '1/2', label: '1/2', batteryLabel: '60%' },
    { value: '3/4', label: '3/4', batteryLabel: '80%' },
    { value: 'F', label: 'F', batteryLabel: '100%' },
  ];

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-12 animate-in fade-in duration-700">
      <div className="mb-12">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-10 h-1 bg-fuchsia-600"></div>
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-fuchsia-600">Fleet Operations</p>
        </div>
        <h1 className="text-3xl md:text-4xl font-black text-slate-950 uppercase tracking-tight leading-tight">Kelola Unit Bertugas</h1>
        <p className="text-slate-500 font-bold text-xs uppercase tracking-widest mt-2">Pilih unit untuk konfirmasi balik ke pool</p>
      </div>

      {submitted === 'returned' && (
        <div className="mb-10 p-7 bg-green-600 text-white rounded-[2rem] flex items-center gap-5 shadow-2xl animate-in zoom-in duration-500">
          <div className="bg-white text-green-600 p-3 rounded-2xl shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polyline points="20 6 9 17 4 12"/></svg>
          </div>
          <div>
            <p className="font-black text-xl leading-none mb-1 uppercase tracking-tight">Data Berhasil Disinkron!</p>
            <p className="text-sm opacity-90 font-bold uppercase tracking-tighter text-green-50">Status armada kini tersedia untuk user lain.</p>
          </div>
        </div>
      )}

      {!selectedLogId ? (
        <div className="space-y-6">
          {activeLogs.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center">
              <p className="text-slate-400 font-black uppercase text-xs tracking-[0.2em]">Tidak ada unit yang sedang bertugas.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {activeLogs.map(log => (
                <div key={log.id} className="bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-xl transition-all group overflow-hidden relative">
                  <div className="flex justify-between items-start mb-6">
                    <div className="p-4 bg-slate-950 text-white rounded-2xl group-hover:bg-fuchsia-600 transition-colors">
                      <Icons.Car />
                    </div>
                    <div className="text-right">
                       <span className="text-[9px] font-black px-3 py-1 bg-fuchsia-100 text-fuchsia-600 rounded-full uppercase tracking-widest block mb-1">On Duty</span>
                       <span className="text-[9px] font-mono font-bold text-slate-400">KM Awal: {log.startOdometer}</span>
                    </div>
                  </div>
                  <h3 className="text-xl font-black text-slate-950 leading-none mb-1">{log.carName}</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">{log.driverName} • {log.department}</p>
                  <button onClick={() => setSelectedLogId(log.id)} className="w-full py-4 bg-slate-950 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-fuchsia-600 transition-all shadow-lg active:scale-95">Selesaikan Trip Sekarang</button>
                </div>
              ))}
